"use client";

import { useEffect, useMemo, useRef, useState } from "react";

type Lang = "zh" | "en";
type Text = { zh:string; en:string };
type Talk = {
  id:string; track:"native"|"vibe"; type:"观点"|"方法论"|"案例"|"工具";
  title:Text; speaker:Text; role:Text; overview:Text; core:Text[]; points:Text[];
  images?:string[]; recommended?:boolean; reason?:Text;
};

const t=(zh:string,en:string):Text=>({zh,en});
const talks:Talk[]=[
  {id:"N01",track:"native",type:"观点",title:t("智能、艺术与人机协作的底层关系","Intelligence, Art and Human–AI Collaboration"),speaker:t("分享嘉宾（现场记录未注明姓名）","Guest speaker (name not captured)"),role:t("AI 原生创新分论坛分享嘉宾","D20 AI-Native Innovation speaker"),overview:t("从生命演化与电影影像本体论出发，讨论智能是什么、艺术为何不可被纯粹计算，以及人在人机协作中的位置。","A philosophical opening on intelligence, cinematic ontology, and why human experience remains central to creation."),core:[t("分享把智能放回漫长的生命演化史中理解：复制、反应、理解、心智、语言与文字，是生命为了延续而逐层形成的能力。","Intelligence is traced through evolution—from replication and reaction to mind, language and writing."),t("AI 生成影像没有现实世界中的原型，它改变了电影影像作为现实“索引”的传统基础，也迫使创作者重新回答什么是作品。","AI imagery has no physical referent, challenging cinema’s traditional status as an index of reality."),t("演讲提出 O = (H + A) × e^(λH) 的人机协作模型。AI 提供能力，人类经验 H 则决定这种能力会被激发到什么程度。","The proposed collaboration model places human intelligence as the exponential amplifier of AI capability.")],points:[t("艺术中的空白、偶得、转向与不可言说，并不是需要消除的噪声。","Ambiguity, chance and the unsayable are not noise to be removed."),t("AI 可以模拟形式，但作品为何成立仍依赖人的生命经验与表达动机。","AI may simulate form, but human experience gives a work its reason to exist.")],images:["/d20/am-1.png"],recommended:true,reason:t("作为整场上午论坛的思想入口，它能帮助设计师先建立判断框架，再理解后续工具和工程实践。","A useful conceptual frame before entering the later tools and engineering practices.")},
  {id:"N02",track:"native",type:"观点",title:t("设计师的焦虑、品味与 Skill 封装","Anxiety, Taste and Packaging Design as Skills"),speaker:t("分享嘉宾（现场记录未注明姓名）","Guest speaker (name not captured)"),role:t("AI 产品与设计实践者","AI product and design practitioner"),overview:t("一场节奏轻快但问题尖锐的分享：当设计能力被写成 Skill、风格可以大规模调用，品味是否仍然是设计师的护城河？","A sharp discussion of what happens when taste and design capability become reusable AI skills."),core:[t("设计师的焦虑不只来自 AI，而是来自“会使用 AI 的人”。与此同时，工具学习成本正在快速下降：越晚使用，工具可能越不需要学习。","Design anxiety increasingly comes from people who use AI well, while tools themselves require less learning."),t("品味被拆分为约束与敏感性。约束可以写成规则，敏感性则来自长期经验、文化处境与对细微差异的感知。","Taste is separated into constraints and sensitivity; only the former is easily encoded."),t("当一种优秀风格被封装并被大量调用，它会迅速进入大众审美，继而成为新的默认样式。Skill 既放大品味，也可能让品味贬值。","Once a style is packaged and widely reused, it can quickly become another visual default.")],points:[t("Skill 的上限取决于编写者的认知上限。","A skill can only be as good as its author’s understanding."),t("不要只把结果写进 Skill，更要把判断与方法写进去。","Encode judgment and method, not merely outputs.")]},
  {id:"N03",track:"native",type:"案例",title:t("AIGC 影像产业：从生成繁荣到作者性回归","AIGC Film: From Generation Boom to Authorship"),speaker:t("北影节 AIGC 单元相关分享嘉宾","Representative of the BJIFF AIGC programme"),role:t("AI 影像产业观察与实践者","AI film industry practitioner"),overview:t("通过北影节 AIGC 单元三年的作品与数据，观察技术进步、审美趋同和长内容创作的真实瓶颈。","Three years of festival data reveal rapid technical gains, aesthetic convergence and the bottlenecks of long-form AI film."),core:[t("投稿量由 430 部增长至约 3000 部，作品在分辨率、微表情、口型和跨镜一致性上显著进步。","Submissions grew from 430 to roughly 3,000, with rapid gains in fidelity and consistency."),t("44.9% 的作品选择超写实风格，说明模型能力提升并不自动带来新的影像语言。大量作品只是完成生成，还没有进入创作。","44.9% of works adopted hyperrealism, showing that technical progress does not automatically create new visual language."),t("《七日浮生》把导演真实潜水事故转化为病床意识流；《牡丹记》反向利用模型幻觉。两者都回答了“为什么非 AI 不可”。","Winning works used personal experience or model hallucination in ways that made AI integral rather than incidental.")],points:[t("创造力向生成之前位移：数据、训练、清洗、选择和拒绝都属于创作。","Creativity moves upstream into data, training, selection and rejection."),t("长片的主要难题仍是人物、空间和世界观跨镜头的一致性。","Long-form work still struggles with identity, space and world consistency.")]},
  {id:"N04",track:"native",type:"方法论",title:t("从 Design 到 Build：把设计流程翻译成 Agent Loop","From Design to Build: Translating Design into an Agent Loop"),speaker:t("Code Work / AI 原生产品团队分享嘉宾","Code Work / AI-native product team"),role:t("AI 原生产品与设计工程实践者","AI-native product and design engineering practitioner"),overview:t("设计师进入真实代码库后，如何让设计系统、规则和质量检查成为 Agent 可以持续执行的机制。","How design systems, rules and quality checks become mechanisms an agent can execute continuously."),core:[t("设计师不再只交付设计稿，而是在 monorepo 中维护真实运行的设计系统 package，并直接参与产品代码。","Designers maintain executable design-system packages inside the product codebase."),t("三层体验保障包括：Agent CMD 保护核心组件，UI Check 扫描违规颜色与重复造轮子，巡检 Agent 监控绕过评审的提交。","Three safeguards protect core components, scan UI violations and monitor unreviewed changes."),t("Code Work 把设计过程拆为确认边界、制定计划、获取上下文、生成、质量门禁，以及用户的 Nudge 与 Frame。","The design process becomes a loop of boundaries, planning, context, generation, quality gates, nudge and frame.")],points:[t("AI 生成质量首先取决于代码库与设计系统是否清晰。","AI output quality starts with a clear codebase and design system."),t("设计的新边界，是为人与 Agent 之间的对齐机制而设计。","The new design boundary is the alignment mechanism between people and agents.")],images:["/d20/am-4.png","/d20/am-5.png"]},
  {id:"N05",track:"native",type:"方法论",title:t("Runtime Design 与面向 Agent 的设计资产","Runtime Design and Agent-Readable Assets"),speaker:t("千问云 / 阿里云设计团队分享嘉宾","Qwen Cloud / Alibaba Cloud Design team"),role:t("AI 原生设计语言与平台实践者","AI-native design language practitioner"),overview:t("从网页设计工具史讲到人机平权平台：未来的网站不仅要让人看懂，也要让 Agent 能读取、操作和完成任务。","A history of interface tools leading to sites that agents can read, operate and act upon."),core:[t("Token、样式、字体梯度、组件与交互原则被代码化，设计资产从图纸变成可调用的 Code Block。","Tokens, typography, components and interaction principles become callable code assets."),t("面向 Agent 的界面需要清晰语义、可访问代码、方向说明、Design.md、llm.txt 与可执行 Skill。","Agent-facing interfaces need semantics, accessible code, Design.md, llm.txt and executable skills."),t("Design in Runtime 意味着设计在真实运行环境中被组织、点击和修改，交付物本身就是可继续工作的系统。","Design in Runtime makes the deliverable an operable system rather than a static specification.")],points:[t("Human Read 与 Agent Read 不是两套产品，而是同一体验的两种阅读层。","Human Read and Agent Read are two layers of one experience."),t("作品集也将从 PDF 转向可交互、可运行的网站。","Portfolios will move from PDFs to interactive, running sites.")],images:["/d20/am-6.png"]},
  {id:"V01",track:"vibe",type:"方法论",title:t("意图驱动的 AI 设计新范式：Vibe Designing","Vibe Designing: An Intent-Driven AI Design Paradigm"),speaker:t("杨涛","Yang Tao"),role:t("阿里云 AI Native 产品设计负责人","Head of AI-Native Product Design, Alibaba Cloud"),overview:t("从 Pixels 到 Vibe：设计师不再从执行末端开始，而是从体验、调性与意图的源头定义系统。","A move from pixels to intent: designers define experience, tone and rules before generating interfaces."),core:[t("AI Coding 已从开发者的独门工具变为通识创造能力。设计师可以从使用工具走向制作自己的工具。","AI coding is becoming a general creative capability, allowing designers to build their own tools."),t("Agent 产品的体验会随用户意图实时组织。设计师不再画出所有页面，而是定义生成式 UI 的规则、边界和反馈。","Agent experiences are organized in real time; designers define rules, boundaries and feedback rather than every screen."),t("完整方法包括上下文组织、风格规约、生成、评价与迭代。作品集也应成为能承载叙事、文化理解与 AI 能力的动态网站。","The workflow combines context, style specifications, generation, evaluation and iteration.")],points:[t("设计起点从像素和图层上移到“我要什么体验”。","The starting point moves from layers to the intended experience."),t("临时界面可以变化，但生成它的体验原则必须稳定。","Interfaces may be temporary; the principles generating them must be stable.")],images:["/d20/pm-1.png"],recommended:true,reason:t("它最直接解释了设计师的工作对象正在如何变化，也与团队接下来做 AI 产品、作品集和设计系统高度相关。","It most directly explains how the designer’s object of work is changing.")},
  {id:"V02",track:"vibe",type:"案例",title:t("设计的翻译力：AI 如何进入千行百业","Design as Translation: Bringing AI into Industry"),speaker:t("王婉","Wang Wan"),role:t("阿里云政企设计负责人","Head of Government & Enterprise Design, Alibaba Cloud"),overview:t("从企业业务场景讨论设计如何翻译复杂专业知识，并把优秀项目、行业经验和解决方案沉淀为可检索资产。","How design translates specialised knowledge and turns project experience into searchable organisational assets."),core:[t("企业 AI 设计不是套用统一界面，而是理解行业语言、业务目标、使用环境和决策链，再把它们转译为产品体验。","Enterprise AI design translates industry language, goals, environments and decision chains into product experiences."),t("优秀项目库不应只是视觉参考集合，还需要保留问题、策略、方法、结果与适用条件。","A project library should retain problems, strategies, methods, outcomes and conditions—not just screenshots."),t("语义检索让设计师能从组织历史中找到相似问题和成熟解法，降低重复研究与寻找参考的成本。","Semantic retrieval helps teams recover proven solutions from organisational memory.")],points:[t("设计师的价值是跨专业语境进行准确翻译。","Designers create value by translating accurately across professional contexts."),t("知识库的检索质量，取决于沉淀时是否保留了结构和背景。","Retrieval quality depends on structure and context captured at the time of documentation.")],images:["/d20/am-3.png"]},
  {id:"V03",track:"vibe",type:"案例",title:t("弥合与生成：AI 时代传统艺术的新边界","Bridging and Generating: Traditional Art in the AI Era"),speaker:t("沈乐平","Shen Leping"),role:t("中国美术学院书法学院副院长、博士生导师","Deputy Dean, School of Calligraphy, China Academy of Art"),overview:t("以书法与篆刻工作坊为例，展示专业审美如何介入模型训练，并重新讨论传统、技术、版权和创作主体。","A calligraphy and seal-carving workshop explores professional aesthetics, model training, copyright and authorship."),core:[t("团队从北魏墓志、智永千字文、草书与颜真卿等经典范本采集高清数据，训练具有风格意识的模型。","The team collected high-resolution data from canonical works to train style-aware models."),t("难点不是生成像毛笔字的图，而是把气、韵、法、虚实相生等抽象判断转化为模型可处理的数字逻辑。","The challenge is translating concepts such as qi, rhythm and negative space into machine-processable logic."),t("项目建立作品编号、存证日期与数字身份，探索国内较早一批具备数字版权的人机共创书法作品。","The project explored digital identity and copyright for human–AI co-created calligraphy.")],points:[t("AI 是器、是客；人是魂、是主体。","AI is the instrument; the human remains the creative subject."),t("传统不是静止教条，而是在工具、社会与审美碰撞中持续更新。","Tradition is not static doctrine but a practice continually renewed through change.")],recommended:true,reason:t("它把看似距离最远的传统书法与 AI 放在一起，能刷新设计师对“创新必须抛弃传统”的惯性理解。","It challenges the assumption that innovation requires abandoning tradition.")},
  {id:"V04",track:"vibe",type:"工具",title:t("从设计资产到 OPC：让个人能力可复用、可商业化","From Design Assets to OPC"),speaker:t("AJ","AJ"),role:t("WaytoAGI 创始人","Founder, WaytoAGI"),overview:t("从产品经理和社区实践出发，讨论如何用 Design.md、知识库与 AI 分身，把风格、内容和工作流变成个人资产。","How Design.md, knowledge bases and AI doubles turn style, content and workflow into reusable personal assets."),core:[t("Design.md 可以从参考网站和既有作品中抽离品牌、颜色、组件和视觉规律，成为模型可理解的风格说明书。","Design.md extracts brand, colour, component and visual rules into a model-readable style specification."),t("个人录音、笔记和网络收藏被结构化进入知识库，作为生成内容时持续补充的上下文。","Recordings, notes and saved references become structured context for generation."),t("Demo 进入市场需要的不只是生成页面，还包括产品流程、用户验证、商业化与持续运营。OPC 强调一个人也能连接完整链路。","Taking a demo to market requires product flow, validation, commercialisation and operations—not just generation.")],points:[t("风格要成为可复用资产，内容要变得结构化。","Style should become reusable assets; content should become structured."),t("AI 降低组建团队的门槛，但执行与进入市场仍然决定结果。","AI lowers team barriers, but execution and market entry still determine outcomes.")]},
  {id:"V05",track:"vibe",type:"案例",title:t("AI 视频生成工作流：从五千条素材到四分钟成片","AI Video Workflow: 5,000 Assets to a Four-Minute Film"),speaker:t("崔一 / 抽象仔","Cui Yi / Chouxiangzai"),role:t("B站 UP 主、前央视导演、抽象世界联合创始人","Creator, former CCTV director, co-founder of Chouxiang World"),overview:t("以商业 MV 项目为例，拆解 AI 视频在人物设定、场景真实感、素材选择与团队协作中的实际成本。","A commercial music-video case revealing the real cost of character, scene, selection and team workflows."),core:[t("四分钟成片由十人团队历时近三个月完成，共生成约五千条可用素材，并消耗大量模型积分。","A ten-person team spent nearly three months and generated around 5,000 usable assets."),t("关键人物先建立四视图和造型设定；场景设计通过真实商业照片约束模型，减少古代建筑中过度规整的“AI 感”。","Character turnarounds and real photographic references constrained identity and scene realism."),t("团队重新分工为艺术概念、人物设定、造型、场景和 AI 生成导演。生成速度提升后，选择、统一和推进客户决策成为主要工作。","Roles shifted toward concept, character, styling, environment and AI generation direction.")],points:[t("AI 视频不是按下生成键，而是大规模选择与持续对齐。","AI video is large-scale selection and continuous alignment."),t("商业创作仍需要流程管理、客户沟通和一致的艺术方向。","Commercial work still demands process, communication and a coherent art direction.")]},
  {id:"V06",track:"vibe",type:"工具",title:t("从图片到 3D 与世界模型：Tripo 的能力演进","Image-to-3D and World Models: Tripo"),speaker:t("Tripo 团队分享嘉宾","Tripo team speaker"),role:t("AI 3D 产品实践者","AI 3D product practitioner"),overview:t("展示图片生成 3D 模型的能力进展，并延伸到场景生成、游戏制作与世界模型的可能性。","Progress in image-to-3D generation, extending toward scenes, game creation and world models."),core:[t("单张或多张参考图可以更快生成可编辑 3D 资产，降低角色、道具和场景原型制作门槛。","Single or multiple images can rapidly produce editable 3D assets."),t("能力从孤立模型逐步延伸到具有空间关系的完整场景，为游戏、影视和空间设计提供新的快速原型方式。","The capability is expanding from isolated objects toward spatially coherent scenes."),t("世界模型的意义不只在视觉生成，而在对空间、物体关系和可交互规则的建模。","World models represent space, object relations and interaction rules—not merely visuals.")],points:[t("3D 生成正在从资产生产走向环境构建。","3D generation is moving from asset production to environment construction."),t("对设计师而言，最直接的价值是更低成本地验证空间与叙事。","For designers, the immediate value is lower-cost spatial and narrative prototyping.")]},
];

// Official programme names, speakers and roles from the D20 sub-forum page.
const official:Record<string,{title:Text;speaker:Text;role:Text}>={
  N01:{title:t("从数据到智慧的认知阶梯","The Cognitive Ladder from Data to Wisdom"),speaker:t("杨树","Yang Shu"),role:t("中国美术学院电影学院制作系主任、中国美术家协会数字艺术艺委会副秘书长","Head of Production, School of Film, China Academy of Art")},
  N02:{title:t("AI-Native Design: Agentic UI与审美驾驭","AI-Native Design: Agentic UI and Aesthetic Direction"),speaker:t("谭啸","Tan Xiao"),role:t("阿里云创新中心高级设计专家 & 秒悟设计负责人","Senior Design Expert, Alibaba Cloud Innovation Center; Design Lead of Miaowu")},
  N03:{title:t("一场从创作到产业的深度跃迁——2026北影节AIGC单元全回顾","A Deep Leap from Creation to Industry — 2026 BJIFF AIGC Review"),speaker:t("唐俊淑","Tang Junshu"),role:t("中国传媒大学动画与数字艺术学院硕士导师 / 影视协同创作研发中心负责人 / 北京国际电影节AIGC单元负责人","Graduate Supervisor, Communication University of China; Head of BJIFF AIGC Programme")},
  N04:{title:t("从 Design 到 Build：Agent 时代体验设计的新边界","From Design to Build: New Frontiers of Experience Design in the Agent Era"),speaker:t("张明华","Zhang Minghua"),role:t("阿里云创新中心设计专家 & Qoder主设计师","Design Expert, Alibaba Cloud Innovation Center; Lead Designer of Qoder")},
  N05:{title:t("AI-Native时代的设计美学与交互体验迁移","Design Aesthetics and Interaction Migration in the AI-Native Era"),speaker:t("杜海航","Du Haihang"),role:t("阿里云创新中心高级设计专家 & 国际化设计负责人","Senior Design Expert and International Design Lead, Alibaba Cloud Innovation Center")},
  V01:{title:t("Vibe Designing：意图驱动的设计新范式","Vibe Designing: An Intent-Driven Design Paradigm"),speaker:t("杨涛","Yang Tao"),role:t("阿里云AI-Native产品设计负责人","Head of AI-Native Product Design, Alibaba Cloud")},
  V02:{title:t("设计的翻译力:解码千行百业，数智迭代跃迁","The Power of Design Translation: Decoding Industries and Digital-Intelligent Evolution"),speaker:t("王婉","Wang Wan"),role:t("阿里云政企设计负责人","Head of Government & Enterprise Design, Alibaba Cloud")},
  V03:{title:t("弥合与生成——AI时代传统艺术的新边界与新可能","Bridging and Generating — New Frontiers for Traditional Art in the AI Era"),speaker:t("沈乐平","Shen Leping"),role:t("中国美术学院书法学院副院长","Deputy Dean, School of Calligraphy, China Academy of Art")},
  V04:{title:t("OPC：一群人正在重新定义AI创作","OPC: A Community Redefining AI Creation"),speaker:t("AJ","AJ"),role:t("WaytoAGI 创始人","Founder, WaytoAGI")},
  V05:{title:t("创作者的游乐场：AI时代的审美与选择","The Creator’s Playground: Aesthetics and Choice in the AI Era"),speaker:t("抽象仔 XEIIZO","Chouxiangzai XEIIZO"),role:t("B站知名UP主、前央视导演、AIGC技术流抽象代表人物、全球短剧榜榜首创作者","Bilibili creator, former CCTV director and AIGC filmmaker")},
  V06:{title:t("从Vibe到Pipeline：AI 3D时代的设计全流程重构","From Vibe to Pipeline: Rebuilding the AI 3D Design Workflow"),speaker:t("朱瓜瓜","Zhu Guagua"),role:t("VAST 品牌视觉负责人","Head of Brand Visuals, VAST")},
};
talks.forEach(x=>Object.assign(x,official[x.id]||{}));
talks.find(x=>x.id==="N01")!.recommended=false;

// The transcript carries substantially more context than the index card. Keep it in the detail view.
Object.assign(talks.find(x=>x.id==="N01")!,{core:[
  t("分享从《人工智能艺术原理》课程展开，先把“人工”与“智能”拆开。智能不是某个模型突然拥有的能力，而是生命为了延续逐层形成的认知阶梯：复制、反应、理解、心智、语言，直到文字把经验跨越时间保存下来。","The talk begins with the course Principles of AI Art and frames intelligence as an evolutionary ladder."),
  t("电影 130 年的美学建立在摄影影像本体论上：镜头拍到的东西曾经真实存在，影像是现实留下的索引。AI 生成影像没有现实原型，这使电影第一次大规模面对一种“没有被拍摄过”的视觉世界。","AI imagery breaks cinema’s traditional indexical relationship with physical reality."),
  t("现场播放的学生作品《恐鸟》把生物大灭绝、智能演化与人类处境连接起来。作品的价值不在于证明模型能生成画面，而在于它用 AI 讨论了一个无法被普通拍摄替代的命题。","The student work Moa used AI to connect extinction, intelligence and the human condition."),
  t("演讲把艺术追溯到约五万年前。艺术的核心不是精确复现，而是生命感、情绪和不可言说的经验。树叶间的空隙、创作过程中的停顿、偶得与转向，都不是应当被流程消除的噪声。","Art is located in life, emotion, pauses and chance rather than pure replication."),
  t("最后以 O = (H + A) × e^(λH) 描述人机协作。AI 能力与人的能力不是简单相加，人的经验、意图和感受会指数级改变输出；人仍然决定作品要表达什么，以及什么结果值得被保留。","The collaboration model places human experience as the exponential amplifier of AI capability.")],points:[t("AI 生成影像改变了电影影像必须指向现实的传统前提。","AI imagery changes cinema’s traditional relation to reality."),t("艺术中的随机、停顿与不可言说，是创作的一部分。","Chance, pauses and the unsayable are part of creation."),t("人的经验和意图决定 AI 能力最终被用于什么。","Human experience and intention determine what AI capability is used for.")],images:["/d20/am-1.png","/d20/am-2.png"]});
Object.assign(talks.find(x=>x.id==="N02")!,{core:[
  t("谭啸从设计师对 AI 的焦虑谈起：真正带来压力的往往不是工具本身，而是能把工具更快变成产品的人。与此同时，工具的工程层越来越厚，操作越来越自然，“学得越晚，越不用学”成为一种现实趋势。","The talk begins with design anxiety and the rapidly falling operational cost of AI tools."),
  t("秒悟支持用户通过自然语言创建应用，并继续完成域名、登录与发布。它把传统上依赖开发协作的最后环节一并纳入，让设计师可以更直接地把意图变成可分享的真实产品。","Miaowu extends natural-language creation into domains, authentication and deployment."),
  t("分享把品味拆为“约束”与“敏感性”。约束可以被规则化，敏感性则来自长期经验：它让设计师发现一个结果虽然满足规则，却仍然不准确、不自然或不属于当前语境。","Taste combines codifiable constraints with sensitivity grounded in experience."),
  t("当优秀风格被封装成 Skill 并被大量调用，它会迅速进入大众审美，最终成为新的默认样式。这解释了为什么 AI 作品越来越精致，却也越来越相似。","Widely reused style skills can become a new default aesthetic."),
  t("关于 Skill 的实践建议包括：核心逻辑应亲手编写；传递方法而不只是成品；警惕历史经验固化成限制；让真实项目持续检验 Skill。个人认知最终决定了 Skill 的上限。","Skill-building principles emphasise authored logic, transferable method and real-world testing.")],points:[t("AI 可以执行约束，但无法自动获得设计师的敏感性。","AI can execute constraints but does not automatically acquire sensitivity."),t("风格被规模化复用后，可能快速变成默认审美。","Scaled reuse can quickly turn a style into a default."),t("Skill 的上限来自编写者理解问题的深度。","A skill’s ceiling comes from the author’s depth of understanding.")],images:["/d20/am-3.png"]});
Object.assign(talks.find(x=>x.id==="V01")!,{core:[
  t("杨涛先把 AI Coding 定义为新的通识创造能力。团队中的设计师不只用现有工具，而是为自己的具体问题制作小工具、发布代码包，并把一次个人尝试变成其他人可复用的能力。","AI coding is framed as a general creative capability, allowing designers to build and share tools."),
  t("Vibe Designing 的起点不是像素、图层和栅格，而是“我要什么体验、什么调性”。设计师先定义意图，再把模糊的感受翻译成模型能理解的上下文、规则与评价标准。","Vibe Designing starts from intended experience and tone rather than pixels and layers."),
  t("Agent 产品的界面会根据用户意图实时组织。过去设计信息架构与固定流程，今天则要设计动态交互、生成式 UI 和系统如何举一反三。设计师交付的是组织体验的规则，而不是穷举所有页面。","Agent interfaces are organised in real time, shifting design from fixed screens to generative rules."),
  t("为了让 AI 更接近预期，需要把设计系统从 only for humans 推进到 for both human and AI。组件、Token、语义、交互原则和设计说明要同时可被人阅读，也可被 Agent 调用。","Design systems must become readable by both humans and agents."),
  t("演讲最后把变化落到作品集：设计师仍然用作品说话，但未来的作品不再只是 PDF，而是一个可以交互的动态网站，凝聚文化理解、叙事、品味和使用 AI 的能力。","The talk concludes that portfolios should become interactive sites rather than static PDFs.")],points:[t("设计起点从执行末端上移到体验意图。","The starting point moves upstream from execution to experience intent."),t("生成式界面可以变化，生成它的原则必须清晰。","Generated interfaces may vary, but their principles must be clear."),t("设计系统需要同时服务 Human Read 与 Agent Read。","Design systems must support both Human Read and Agent Read.")]});
Object.assign(talks.find(x=>x.id==="V03")!,{core:[
  t("沈乐平先用书法史说明传统从未停止变化：从甲骨金文、秦代统一文字、汉代隶变，到魏晋风度、唐代法度、宋人尚意和清代碑学，工具、社会与审美不断推动书法突破边界。","The talk begins by showing that calligraphy has always evolved through tools, society and aesthetics."),
  t("在 AI 时代，难点不是让模型生成“像毛笔字”的图，而是让它理解长与变、雅与俗、正与奇，以及气、韵、法等传统美学中指向并不完全确定的概念。","The challenge is not brush-like imagery but translating nuanced aesthetic judgment into computational logic."),
  t("中国美院书法学院与阿里云设计中心发起工作坊，从北魏墓志、智永千字文、草书与颜真卿等经典范本采集高清数据，进行风格训练和杂糅实验，模拟传统学习中的取法路径。","The workshop trained and blended styles using high-resolution data from canonical works."),
  t("篆刻实验从数千方古代汉印中采集数据，完成模型训练和风格迁移。生成结果不仅模拟文字和章法，也尝试表现冲刀、切刀、残破，以及计白当黑、虚实相生的语言特质。","Seal-carving experiments modelled composition, cutting traces, erosion and negative space."),
  t("演讲明确区分主客：AI 是器、是客，擅长数据与运算；人是魂、是主体，负责气韵、心性、意境、生命体感和最终审美甄别。技术帮助进入经典，但探索未知仍然属于人。","AI is the instrument; the human remains the subject responsible for judgment and exploration."),
  t("项目还建立版数编号、存证日期与数字身份，探索人机共创书法的数字版权。它不仅是作品实验，也同时涉及创作、理论和教学方法的更新。","The project also explored digital identity and copyright across creation, theory and education.")],points:[t("传统书法一直在变化，AI 是新的工具变量而不是传统的终点。","AI is a new tool in a tradition that has always evolved."),t("专业审美必须进入数据采集、训练与结果甄别。","Professional aesthetics must guide data, training and evaluation."),t("AI 是器，人是主体；人的任务是判断并探索未知。","AI is the instrument; humans judge and explore the unknown.")],images:["/d20/am-1.png","/d20/am-2.png"]});
Object.assign(talks.find(x=>x.id==="N03")!,{core:[
  t("唐俊淑以北京国际电影节 AIGC 单元发起者与产业观察者的双重身份回顾三年变化。单元从 2023 年启动，第一年收到约 430 部作品，之后增长到约 3000 部，并逐步建立赛事、学术、技术、孵化与产业落地相互连接的结构。","Tang Junshu reviews three years of the BJIFF AIGC programme as both founder and industry observer."),
  t("早期作品常带有 PPT 动画般的质感，角色、镜头和声音难以稳定。到 2026 年，分辨率、微表情、口型同步和跨镜头一致性都有明显提升。技术进步让更多人进入创作，也让评审开始面对数量与类型快速扩张的新局面。","Technical quality advanced rapidly in resolution, expression, lip sync and cross-shot consistency."),
  t("本届首次设置长片、短片和剧集三类竞赛单元。这个变化不只是赛道增加，而是主流电影节开始承认 AI 长内容具有独立讨论的价值，并尝试建立从赛事到产业的完整支撑。","New feature, short-film and series categories signal institutional recognition of long-form AI work."),
  t("繁荣也暴露出审美趋同：44.9% 的作品选择超写实风格。模型默认能力、热门提示词和共同参考让大量作品看起来完成度很高，却缺少作者必须使用 AI 的理由。分享用“准入者—表达者—突破者”的金字塔说明，真正形成新语言的作品仍然很少。","The boom also reveals aesthetic convergence, with 44.9% of works adopting hyperrealism."),
  t("最佳长片《七日浮生》来自导演真实的潜水事故与病床经历。作品把身体受限时的意识流动转化为影像，AI 不是附加效果，而是表达这种主观经验的必要媒介。","The feature winner Seven Days of Floating Life transformed a real diving accident into subjective imagery."),
  t("最佳短片《牡丹记》没有尽力修正模型幻觉，而是反向使用非人类的视觉逻辑，形成突破物理规律的东方美学。两个案例都表明，优秀作品不是生成得更像，而是知道为什么要使用模型的不稳定性。","The short-film winner Peony used model hallucination as an Eastern visual language."),
  t("分享最后把创造力的位置向前移动：点击生成只是消费，真正的创作发生在数据选择、训练、清洗、取舍与判断中。由人的审美一点点喂养出来的模型与作品，构成了人和技术的共生创作主体。","Creativity moves upstream into data selection, training, cleaning, judgment and rejection."),
  t("长内容仍面临人物身份、空间、时间和世界观的持续一致性问题。技术指标与创作者期待之间仍有明显差距，因此产业化不仅需要更强模型，也需要新的流程、协作方式和质量标准。","Long-form production still struggles with identity, space, time and world consistency.")],points:[t("投稿规模与技术质量快速提升，但“生成”仍不等于“创作”。","Scale and quality grew quickly, but generation is not equivalent to creation."),t("作者性体现在生成之前的选择、训练、判断和拒绝。","Authorship appears in choices, training, judgment and rejection before generation."),t("模型幻觉可以成为语言，前提是创作者知道它为何服务于表达。","Hallucination can become language when it serves a deliberate expression."),t("长内容产业化需要一致性、流程和评价体系共同成熟。","Long-form industrialisation requires consistency, workflow and evaluation standards.")]});
Object.assign(talks.find(x=>x.id==="N04")!,{core:[
  t("张明华用两组数据开场：一边是“设计已死”在五个月内被重复宣布 847 次；另一边是他在 Code Work 和 Code IDE 中留下的大量提交与近百万行代码。对比说明设计师的工作并没有消失，而是进入代码库、组件系统、CI 和长期维护。","Zhang contrasts repeated claims that design is dead with his own extensive code contributions."),
  t("他首先区分 coding 与 code。把想法翻译成第一版可运行结果的 coding 正在变便宜；但能进入真实产品、长期维护的好代码并没有自动变便宜，优秀体验也不会因为第一版生成更快而自然出现。","Coding is becoming cheap, but maintainable code and good experience are not."),
  t("在 Code Work 中，设计系统不再只是 Figma Library，而是 monorepo 中真实运行的 workspace package。业务代码消费组件、Token 与样式；设计师则可以在 playground 中验证不绑定业务数据的交互、动效和响应状态。","The design system becomes a real workspace package inside the monorepo."),
  t("为了避免高产能 Agent 逐渐掏空设计系统，团队建立第一层约束 Agent CMD：核心组件、Token 和变量是“设计圣域”；业务必须先消费已有组件；修改核心库必须得到明确的人类许可。","Agent CMD establishes the first layer of design-system boundaries."),
  t("第二层是 UI Check 工程门禁。脚本读取 Token 与组件库，扫描业务 UI 是否使用硬编码颜色、随意引入图标库，或重复创建按钮、对话框和卡片。它不能判断品味，但能挡住最常见的系统漂移。","UI Check scans hard-coded colour, icon misuse and duplicated components."),
  t("第三层是巡检 Agent。它阅读代码提交、群聊、需求评论和 PRD，识别没有产品与设计参与痕迹却直接合入主干的交互变化，并在协作群中提醒责任人。三层机制把体验一致性放入系统循环，而不是依赖一个设计师肉眼盯住所有提交。","A patrol agent monitors commits, chats and requirements for changes that bypass design review."),
  t("随后分享转向 Build。Agent 被比喻成只能发声的囚徒：模型本身不能行动，只能判断并调用 read、edit、write、bash 等工具。工具结果返回上下文，模型继续判断，直到任务完成，这就是 Agent Loop。","An agent is compared to a prisoner who can speak but acts only through tools."),
  t("Design Agent 把设计师方法翻译为可执行顺序：先确认设计边界；生成设计简报；按优先级获取用户请求、设计系统与参考；产出可继续工作的 React 或 HTML；执行占位文案、编造数据、默认蓝紫渐变、窄屏适配等质量检查；最后通过 Nudge 调方向、用 Frame 把画面区域连接到真实代码。","The Design Agent follows boundaries, brief, context, artifact, quality checks, nudge and frame."),
  t("这套流程的核心是对齐两端的不确定性：用户可能说不清需求，模型也可能理解偏差。设计师的工作从画输入框或美化结果，转向设计澄清意图、补足上下文、暴露过程、评估结果与允许接管的机制。","The central design task becomes alignment between uncertain user intent and uncertain AI output."),
  t("在 Agent 时代，设计师会更多承担评估者角色：把“页面太乱”转化为可执行反馈，把体验目标变成 Checklist、Audit、Adapt 与 Polish 的循环。系统需要评估、回滚和讨论的缓冲，而不是把速度作为唯一指标。","Designers increasingly define executable critique, evaluation and rollback mechanisms.")],points:[t("Coding 变便宜，不等于好代码和好体验变便宜。","Cheap coding does not make maintainable code or good experience cheap."),t("设计系统需要软约束、工程门禁和协作巡检共同维护。","Design systems require soft rules, engineering gates and collaboration monitoring."),t("Build 是把模型、工具、上下文、质量门禁和反馈组织成持续工作的系统。","Build organises models, tools, context, quality gates and feedback into a working system."),t("设计师的新边界是定义对齐、评价、信任与人类接管机制。","The new design boundary covers alignment, evaluation, trust and human takeover.")]});
Object.assign(talks.find(x=>x.id==="N05")!,{core:[
  t("杜海航把分享定义为一个仍在变化中的观察，而不是确定结论。他从数字体验史出发：个人电脑带来 GUI，浏览器带来网页，Flash、HTML5、WebGL 与智能手机不断扩展设计师能够创造的体验。技术与设计边界之间存在持续的因果关系。","Du frames the talk as an evolving observation grounded in the history of digital experience."),
  t("网页美学也随工具迁移：从超文本、网页三剑客与图库素材，到 Adobe、Sketch、Figma、Cinema 4D、Blender、Processing 与 WebGL。今天，AI Coding 工具和生成模型继续叠加在工具链上，并没有简单淘汰过去的方法。","Web aesthetics evolve through an accumulating toolchain rather than simple replacement."),
  t("生成式 AI 之后，主流页面从强调三维科技感，转向更有艺术感、植物感和有机感的视觉。千问云将新的语言称为 Organic Intelligence，并通过代码与 AI 共同定义它的组件、动效和表达。","Generative AI contributes to a more organic and artistic visual language."),
  t("千问云被设计为面向开发者与 Agent 的 API 平台。它强调“人机平权”：网站的用户不再只有人，Agent 需要真正浏览、比较模型、购买并进入控制台操作，而不只是读取网页文字。","Qwen Cloud is designed as an API platform for both developers and agents."),
  t("传统网站可以拆成原子组件、交互范式和任务机制；面向 Agent 时，这些设计资产都要再被代码化。组件必须 accessible from code，设计系统的核心不只是说明文档，而是 Code Block、Token、命令行、Design.md 和可执行 Skill。","Agent-facing design assets must become accessible code, blocks, tokens and executable skills."),
  t("以往嵌入页面的 Banner、GIF 或产品视频只方便人观看。千问云把产品演示组件做成可点击、可交互的代码：人能更直接理解产品，Agent 也能通过语义与代码识别组件表达的内容和可执行动作。","Interactive code components serve both human understanding and agent interpretation."),
  t("团队的设计同学在 AI 辅助下贡献超过二十万行代码。这里的重点不是要求设计师手写全部代码，而是代码工具本身已经成为设计工具，设计师可以直接参与组件、规范与体验的真实构建。","AI-assisted code becomes a design medium, with designers contributing directly to the system."),
  t("最终交付方式从画出所有页面，迁移到用代码定义 Principle、原子组件和规范，再实时生成完整平台。杜海航将它概括为 Design in Runtime：设计不是一张静态图，而是在运行环境中可以被操作、交互和继续修改的数字体验。","The final shift is Design in Runtime: an operable, interactive and modifiable experience.")],points:[t("设计美学与生产方式始终受技术媒介推动。","Design aesthetics and production methods are shaped by technical media."),t("AI-Native 平台必须同时为人和 Agent 提供可理解、可执行的体验。","AI-native platforms must be understandable and executable by both people and agents."),t("代码块、Token、命令行和 Skill 正成为设计系统的真实资产。","Code blocks, tokens, commands and skills become real design-system assets."),t("Design in Runtime 让交付物从静态图转为持续运行的体验。","Design in Runtime turns the deliverable from a static image into a living experience.")]});

talks.push(
  {id:"N06",track:"native",type:"案例",title:t("一位艺术家和他的新搭档","An Artist and His New Partner"),speaker:t("Loh Jahan罗杰瀚","Loh Jahan"),role:t("新加坡国宝艺术家","Singaporean national artist"),overview:t("一位拥有近五十年创作经验的艺术家，分享如何把 AI Agent 引入潮玩设计，从手稿、角色设定到完整产品方案，与新的创作搭档共同推进。","An artist with nearly five decades of practice shares an AI-assisted designer-toy workflow."),core:[t("罗杰瀚从传统潮玩流程谈起：一张纸上的角色要经过建模、材质、比例、打样和与工厂反复沟通，常常需要半年，早期甚至要由师傅用泥一点点塑形。3D 建模缩短了时间，但仍依赖完整团队。","Traditional designer-toy production moves through modelling, materials, proportion, prototyping and factory coordination."),t("第一次使用妙鸭时，他上传了一张旧画。Agent 没有直接给出唯一答案，而是询问希望怎样推进、效果是否满意、倾向什么风格。这种一轮轮对话让他联想到过去与工厂师傅共同调整细节的过程。","The agent began with questions and iterative dialogue rather than a single generated answer."),t("生成结果不只是角色主图，还包括表情、动作、漫画延展、盲盒、毛绒和 3D 材质效果。原本需要多个岗位协作的产品表达，被连接为一个连续的创作过程。","The output expanded into expressions, poses, comics, blind-box, plush and 3D material studies."),t("潮玩最耗时的是细节。框选编辑允许艺术家只修改头发、水渍、衣服纹理、颜色、体态或眼神，而不必推翻整个方案。对他而言，这种局部、连续的调整比一次性生成更接近真实设计。","Local editing supports detailed iteration without restarting the whole concept."),t("平台还记录每一步创作过程，回应了艺术家对版权与作品归属的担忧。之后他开始不用参考图，只通过文字描述橙色宇航服、蓝紫头发等设定，与 Agent 逐步逼近脑中的形象。","Recorded steps address provenance, while text-only dialogue enables new character creation."),t("最终交付是一整套设计稿：主图、三视图、表情包、动作、漫画和材质效果。过去需要团队和数月完成的前期工作，现在可以由艺术家与 AI 搭档更快完成，但作品的审美和想象仍来自艺术家本人。","The result is a complete design package created by the artist and an AI partner."),t("分享的转折不在于艺术家被技术替代，而在于长期积累的审美终于能更直接地跨过建模与生产沟通门槛。AI 让创作者不必先成为技术专家，也能把脑中的角色推进到产品形态。","AI helps long-developed aesthetic judgment cross technical production barriers.")],points:[t("AI Agent 更像反复沟通的创作搭档，而不是一次性出图工具。","The agent behaves more like an iterative creative partner than a one-shot generator."),t("局部编辑、完整产品延展与过程存证直接回应潮玩生产的真实痛点。","Local editing, product extensions and provenance address real production problems."),t("技术门槛下降后，艺术家的审美、角色经验与细节判断变得更直接。","Lower technical barriers make the artist’s judgment more directly actionable.")]},
  {id:"V00",track:"vibe",type:"观点",title:t("GO Vibe Designing！","GO Vibe Designing!"),speaker:t("王路平","Wang Luping"),role:t("阿里云设计中心总监","Director, Alibaba Cloud Design Center"),overview:t("云智能专场开场：当 AI 从工具走向伙伴、从执行走向共创，设计进入由意图、感觉与生成共同驱动的新阶段。","Opening remarks for the Cloud Intelligence track."),core:[t("王路平回顾过去三年从 AIGC、Workflow 到 Agentic AI 的变化。AI Coding 不再只是工程能力，而逐渐成为设计师参与创造与构建产品的通识工具。","The opening traces the shift from AIGC and workflows to agentic AI."),t("论坛以 Vibe Designing 为线索，关注设计师如何表达意图、组织动态体验，并在 AI 介入之后重新定位自己的工作边界。","The forum focuses on intention, dynamic experience and changing design boundaries.")],points:[t("AI 从执行工具转向协作伙伴。","AI is moving from execution tool to collaborative partner."),t("设计的关注点从固定结果转向意图与生成过程。","Design shifts from fixed outputs to intention and generation.")]},
  {id:"V07",track:"vibe",type:"案例",title:t("AI原住民：13岁少年的创作与梦想","AI Native: A 13-Year-Old Creator’s Work and Dreams"),speaker:t("吕思彤","Lü Sitong"),role:t("13岁独立开发者","13-year-old independent developer"),overview:t("从灵感到近百件作品，一位 AI 原住民分享超过 4000 小时的学习、项目创作与对未来人机关系的想象。","A young independent developer shares over 4,000 hours of learning and nearly 100 projects."),core:[t("分享从个人进入 AI 领域的路径开始：不是先掌握完整技术体系，而是在真实兴趣和项目目标中持续学习、制作与修正。","The journey began through interests and projects rather than a complete technical curriculum."),t("近百件作品说明低门槛工具如何扩大青少年的创造范围，也提醒设计师观察下一代对代码、产品和 AI 协作的天然理解。","Nearly 100 works show how accessible tools expand young creators’ range."),t("她对未来的想象并不止于更强的生成能力，而是 AI 如何进入学习、生活与社会协作。","Her vision extends beyond generation into learning, life and social collaboration.")],points:[t("AI 原住民把模型视为自然的创作环境。","AI natives treat models as a natural creative environment."),t("持续行动和作品积累比年龄或职业边界更重要。","Sustained making matters more than age or professional boundaries.")]},
  {id:"V08",track:"vibe",type:"观点",title:t("对谈：AI 时代的“一人公司”的审美表达与商业逻辑","Dialogue: Aesthetic Expression and Business Logic of the One-Person Company"),speaker:t("刘飞 × AJ × 抽象仔 XEIIZO","Liu Fei × AJ × Chouxiangzai XEIIZO"),role:t("产品经理、播客主理人 × WaytoAGI 创始人 × AI影视创作者","Product manager and podcaster × WaytoAGI founder × AI filmmaker"),overview:t("围绕 OPC 的商业潜力、生态支持、创作边界与个人资产展开的圆桌讨论。","A roundtable on the commercial potential, support systems and creative boundaries of OPCs."),core:[t("讨论区分了 OPC 与传统自由职业者：重点不只是一个人完成更多工作，而是一个人能否搭建由 AI、工具、流程和外部服务组成的完整系统。","The panel distinguishes an OPC from freelancing through system-building."),t("当执行成本下降，市场更看重能否迅速验证并持续行动。想法本身不再稀缺，把想法推进到用户、产品和商业结果的执行力更重要。","As execution costs fall, rapid validation and sustained action become more valuable."),t("面向所有人的通用产品越来越难。模块化、定制化和围绕具体人群构建的小产品，可能更适合个人公司进入市场。","Modular products for specific audiences may suit OPCs better than universal products."),t("圆桌反复回到个人资产：风格、知识、内容、用户关系和工作流需要持续沉淀，而不是每个项目结束后重新归零。","The discussion repeatedly returns to accumulating style, knowledge, audience and workflow assets.")],points:[t("OPC 的核心是编排系统，不是一个人承担所有劳动。","OPC is about orchestrating a system, not doing every task alone."),t("执行、验证与资产沉淀比单个创意更重要。","Execution, validation and asset accumulation outweigh isolated ideas."),t("更具体、更模块化的产品可能更适合个人公司。","Specific and modular products may be better suited to OPCs.")]}
);

// Edited from the full morning transcript as long-form knowledge-base articles.
const morningLongform:Record<string,Text[]>={
  N01:[
    t("01｜为什么要重新理解“智能”\n杨树的分享并没有直接从某个 AI 工具讲起，而是先回到电影与智能的历史。2025 年是电影诞生 130 周年，摄影机长期决定了人们对电影本体的理解：银幕上的画面虽然不在现场，却对应着现实中曾经存在的物理对象。CG 已经开始松动这种关系，而生成式 AI 让画面可以完全没有现实原型。对电影、动画和数字艺术而言，这并不只是制作方式升级，而是影像与现实之间的索引关系被打破。创作者、观众、产业和艺术教育都必须重新回答：当影像不再来自“拍摄过的世界”，作品的真实性与价值从哪里产生？","01 | Why intelligence must be reconsidered\nThe talk begins with cinema’s 130-year dependence on photographed reality and how AI imagery breaks that indexical relationship."),
    t("02｜《恐鸟》：技术展示之外，先找到值得讲的问题\n现场播放的《恐鸟》是本科三年级学生在一个月课程中完成的作品。每一帧画面、配音和音乐均由 AI 生成，但杨树特别说明，当时的制作效率并不高，技术也远不如今天成熟。之所以选择这部作品，不是为了展示“一个月能做完一部片”，而是因为它把已经灭绝的恐鸟、生物大灭绝和智能演化连接起来。作品首先有一个需要讨论的命题，生成技术才成为表达媒介。这也构成整场分享的第一个判断：衡量作品不能只看速度、算力和数量，真正重要的是作品是否建立了有价值的表达。","02 | Moa: begin with a question worth expressing\nThe student film is not presented as a speed demo but as a work connecting extinction and the evolution of intelligence."),
    t("03｜从复制到文字：智能是一条为了“活下去”的阶梯\n分享随后把智能放进约 41 亿年的生命史。最早的复制智能持续了约 32 亿年，生命通过不断复制对抗熵增；八亿年前神经元出现，生物从等待转向反应和学习；五亿年前多巴胺机制出现，可对应今天强化学习中的奖励逻辑；四亿年前两栖动物登上陆地，理解式智能开始；六千五百万年前，灵长类的抓握、能量获取和群体关系推动心智与初级自我意识发展。十万年前语言开始为世界贴标签，五千年前文字让经验能够跨越个体和时间。大语言模型恰恰建立在这一层符号系统上。回看整个过程，智能的原动力并不神秘：它首先是生命寻找生存方式的能力，杨树将它概括为“活下去”。","03 | Intelligence as a ladder for survival\nThe talk traces replication, reaction, understanding, mind, language and writing as successive ways life learns to survive."),
    t("04｜艺术比文字更早，也不完全服从语言\n艺术大约在五万年前已经出现，远早于成熟文字。印度尼西亚苏拉威西洞穴和法国拉斯科洞穴中的形象，直到今天仍能让人感受到当时创作者的生命力和情感。这个时间差很重要：艺术不是先写好一套文字指令，再把它执行成图像。齐白石作画时不会先准备提示词；墨滴意外落在宣纸上，也可能顺势成为作品的一部分。艺术包含身体经验、偶然、停顿和直抒胸臆，它不能被五千年前形成的文字抽象系统完全替代。今天以语言为入口的生成模型因此天然存在边界：它可以响应描述，却未必拥有描述之外的生命感。","04 | Art predates writing and exceeds language\nCave art, embodied practice and chance show why creation cannot be reduced to a complete set of verbal instructions."),
    t("05｜两条思想路径：以美育代宗教与可计算世界\n杨树把 20 世纪初的两种思想实验并置起来。蔡元培创立国立艺术院时提出“以美育代宗教”，希望用艺术修复近代社会中破碎的人性与信仰；图灵的可计算性理论则尝试用数学解构世界的运行。这两条路径发展到今天，形成艺术工作者和设计师必须面对的思想处境：一边是人的情感、信仰与不可言说，一边是越来越强的计算、模型和自动化。AI 艺术并不是选择其中一边，而是需要重新建立两者的关系。","05 | Aesthetic education and the computable world\nThe talk places Cai Yuanpei’s humanistic project beside Turing’s theory of computation to frame today’s tension between art and AI."),
    t("06｜人机协作不是简单加法\n为了表达这种关系，杨树提出 O = (H + A) × e^(λH)。O 是最终输出，H 是人类智能投入，A 是人工智能投入。若只写成 H + A，AI 只是替代部分人力的效率工具：公司减少人员、机器补足执行，社会并没有获得新的创造增量。加入以 H 为指数的正和模型，是为了强调人的投入会持续激发 AI，而不是随着 AI 增强而归零。人的经验、问题意识、价值判断与审美选择决定模型能力被导向何处。模型可以抬高创作下限，却不能自动决定什么值得创作。","06 | Collaboration is not simple addition\nThe proposed formula treats human intelligence as the exponential force that directs and amplifies AI capability."),
    t("07｜不要把效率当成艺术的第一指标\n分享最后回到创作评价。当短剧每月可以生产数万部，当影像数量远超观众能够消费的时间，继续强调产量只会制造泡沫。学生作品花多少算力、节省多少时间，并不是杨树最关心的问题；一部作品是否真正有价值，才是更难也更重要的判断。对设计师而言，这意味着 AI 的确可以压缩执行时间，但节省下来的时间不应只用于生产更多同类结果，而应回到问题、经验和表达本身。","07 | Efficiency should not be art’s primary measure\nWhen content volume exceeds human attention, value depends on the work’s question and expression rather than output speed.")
  ],
  N02:[
    t("01｜焦虑从哪里来：AI、会用 AI 的人，还是不断变化的标准？\n谭啸以轻松的方式承认，AI 论坛受欢迎的一部分原因就是焦虑。最早的问题是“AI 会不会取代设计师”，但它过于抽象，人无法与模型本身竞争；随后焦虑被改写成“取代你的是会使用 AI 的人”，于是设计师开始购买课程、提示词方法和审美训练。再往后，行业又把品味与认知描述成新的护城河。分享并不是提供一句新的安慰，而是逐个拆开工具、品味与认知，追问这些被反复传播的答案是否真的成立。","01 | Where design anxiety comes from\nThe talk unpacks a moving target: fear of AI, fear of AI users, and the repeated promise that taste will be the next moat."),
    t("02｜工具学习的悖论：学得越晚，越不用学\n从提示词工程、上下文工程到 Agent Loop，模型与用户之间的工程层不断加厚。过去需要写几百行提示词校准的任务，现在可能只需给出目标，Agent 就能自己循环和修正。谭啸用身边设计师的例子说明：一个人可能两年里学习了所有中间工具，另一个人什么都没追，但因为基础能力和判断更强，拿到更成熟的新工具后反而做得更好。AI 没有简单替代某个软件，而是形成新的应用层；工具越自然，Know-how 与认知越直接决定结果。","02 | The paradox of learning AI tools\nAs engineering layers thicken, operational knowledge decays quickly while domain judgment transfers to each new tool."),
    t("03｜秒悟要解决的不是生成页面，而是产品的最后一公里\n秒悟允许用户用自然语言描述应用，通过 Design Mode 与 Plan Mode 澄清想法，随后生成代码、接入百炼模型与云服务、分配域名，并继续处理登录注册、微信小程序和安卓应用等发布问题。分享中的猫咪拍立得案例来自真实团队需求：品牌设计师先创造了一只猫，团队不断请求定制衍生，最终他们没有继续手工制作，而是把需求变成一个任何人上传照片即可生成形象的应用。这里的重要变化不是“AI 会画猫”，而是个人创意可以被封装成其他人能使用的产品。","03 | Miaowu addresses the last mile to a real product\nThe cat Polaroid case shows how a recurring design request becomes a deployed service rather than another manual deliverable."),
    t("04｜人人都能做应用之后，设计问题反而暴露得更多\n门槛下降带来了新的麻烦：很多本可用文档或表格解决的小需求也被做成应用，默认蓝紫渐变和缺乏判断的界面大量出现，最后又回到设计师手中请求“美化”。谭啸借此进入品味问题。Design.md 只能描述较浅的风格外观；一个品牌真正稳定的呈现还需要调性、语言、字体库、素材资产、Token、Motion 与实际案例共同约束。设计不是给生成结果换一层皮，而是根据任务意图判断该采用什么方向。","04 | Universal app-making exposes more design problems\nDefault aesthetics reveal why design cannot be reduced to a surface style file."),
    t("05｜从不确定性到确定性：Design Skill 怎样工作\n他的 Design Skill 不会直接套用一种风格，而是先读取意图和需求，对可能方向进行评分，再让多个 Agent 并行探索。用户选定方向后，系统先用轻量的单一 HTML 验证视觉，再进入完整 React 工程。这实际上复现了设计师从发散到收敛的过程：判断任务、探索可能性、选择方向、形成方案并质检。Skill 的价值不在于储存一套漂亮模板，而在于把可重复的方法组织成模型可以执行的流程。","05 | A design skill moves from uncertainty to commitment\nParallel exploration, selection, lightweight validation and engineering reproduce a real design process rather than applying a template."),
    t("06｜编写 Skill 的四个经验\n第一，最关键的几句话必须由作者亲手写，并且作者要通读自己的 Skill，理解它为什么工作。第二，优秀 Skill 应“授之以渔”，提供解题方法，而不是把一个结果硬塞给模型；教 AI 的过程也像费曼学习法，会迫使作者澄清自身方法。第三，Skill 有历史局限，坏规则会限制强模型，好规则也可能随着模型进步而过时。第四，实践是检验标准：只有亲手完成过任务，才知道哪些经验值得固化。首版大概率并不好，需要在真实使用中迭代。","06 | Four lessons for authoring skills\nOwn the critical logic, encode transferable method, recognise historical limits, and validate everything through practice."),
    t("07｜品味为何不能完全被 Skill 获得\n分享将品味拆成约束和敏感性。Skill 可以写下“要做什么、不能做什么”，却不能让模型因为一个像素偏差而身体不适，也不能让它自动拥有创作者的偏见、爱好和生活感受。模型会把大量样本平均化，形成稳定却庸常的结果；当某种人文衬线、某种构图或某种品牌风格被无限复制，它又会变成新的“AI 味”。风格曾是个人标签，工业化生成让风格变成可购买、可交付的快消品，但拥有一个风格并不等于拥有品味。","07 | Why taste cannot be fully packaged\nSkills encode constraints, but sensitivity comes from embodied perception, preference and discomfort with subtle wrongness."),
    t("08｜最后留下的不是工具，而是解决问题的能力\n谭啸并没有否定工具或 Skill。模型负责兜底、工程决定可实现范围、风格资产帮助提高稳定性，但个人认知仍决定上限。工具一定会过时，今天有效的流程也会变化；不会轻易过时的是理解问题、检验结果和继续学习的方法。对设计师而言，真正要建立的不是一套永远正确的提示词，而是能随着模型变化继续判断和修正的能力。","08 | What remains when tools expire\nModels set a floor and engineering defines possibility, but durable value lies in problem-solving, evaluation and continued learning.")
  ],
  N03:[
    t("01｜从竞赛发起者到产业观察者\n唐俊淑以北京国际电影节 AIGC 单元发起者和负责人的身份回顾三年变化。第一届在 2023 年启动，全球范围内尚缺少专门讨论 AI 影像的主流竞赛平台；投稿从约 430 部快速增长到约 3000 部，参与者从少量技术尝鲜者扩展到导演、动画团队、学生、艺术家和产业机构。她强调，这段历史不仅记录模型升级，也记录创作者如何逐步把新工具放进真实生产。","01 | From competition founder to industry observer\nThe programme’s growth from roughly 430 to 3,000 submissions records both model progress and changing creative participation."),
    t("02｜三年技术变化：从能生成到能维持镜头\n早期作品常像 PPT 动画，人物动作僵硬、清晰度不足，口型与声音难以同步，角色进入下一镜就可能变成另一个人。到 2026 年，高分辨率、微表情、口型、复杂运镜和跨镜头一致性已有明显进步。技术提升降低了准入门槛，也改变了评审标准：当“看起来像一部片”不再稀缺，作品必须在叙事、作者性和影像语言上提供更多理由。","02 | From generation to continuity\nAs visual fidelity and shot consistency improve, evaluation moves from technical novelty toward narrative and authorship."),
    t("03｜长片、短片与剧集：为什么赛道变化很重要\n本届首次设立长片、短片和剧集三个竞赛单元，并通过大师工作坊、产业论坛、荣誉盛典与技术伙伴合作，把赛事与学术、技术、孵化和商业落地连接起来。设立长内容赛道意味着主流节展开始承认 AI 电影不仅是短视频或实验片，也可能进入更复杂的工业流程。与此同时，长片对人物、场景、时间和世界观一致性的要求，也暴露了现阶段最困难的问题。","03 | Why long-form categories matter\nFeature, short and series tracks connect competition to workshops, technology and industrial development while exposing consistency bottlenecks."),
    t("04｜繁荣背后的默认美学\n数据中有 44.9% 的作品选择超写实风格。模型擅长的画面、热门提示词和共同参考让作品迅速趋同：它们精致、完整，却经常没有创作者个人的视觉判断。唐俊淑用一个金字塔描述现状：最底层是大量能够进入生成的准入者；再往上是能借助 AI 清楚表达的创作者；最少的是突破者，他们创造模型出现之前不存在的新影像语言。技术普及扩大底座，却不会自动增加塔尖。","04 | The default aesthetic behind the boom\nHyperrealism dominates 44.9% of entries, revealing a large gap between access, expression and genuine breakthrough."),
    t("05｜《七日浮生》：个人经验为什么无法被替代\n最佳长片《七日浮生》建立在导演真实潜水事故上。被困病床时，身体无法行动，意识却在记忆、恐惧和现实之间漂移。传统拍摄很难稳定呈现这种没有明确物理空间的主观经验，AI 生成让意识流、身体感和非现实场景可以连续转化。作品成立的原因不是技术难度最大，而是创作者有一段无法由别人代替的经验，并找到了只有这种媒介才能承载的方式。","05 | Seven Days of Floating Life\nA real diving accident becomes an irreplaceable subjective experience expressed through fluid, non-physical AI imagery."),
    t("06｜《牡丹记》：把模型幻觉变成语言\n最佳短片《牡丹记》没有把 AI 的非物理变化视为错误，而是有意识地利用幻觉、形体漂移和不符合现实的空间关系，形成东方美学语境中的新表达。如果创作者只是修正模型，让它更像摄影，AI 永远只是低成本替代；当创作者理解模型的异常并让它服务叙事，技术缺陷才可能转化为语言。这个案例回答了“为什么非 AI 不可”的另一种可能。","06 | Peony\nThe work turns hallucination and non-physical transformation into a deliberate Eastern visual language."),
    t("07｜创造力发生在生成之前\n唐俊淑引用学院观点：只点击生成更接近消费，不足以构成创作。真正的创造发生在更前面——选择什么数据、怎样训练和清洗、保留什么、拒绝什么、用怎样的审美判断持续喂养模型。“模型即作品”并不是说模型取代成片，而是说模型、数据和人的判断共同构成创作主体。生成按钮只是漫长决策链中的一个节点。","07 | Creativity happens before generation\nData selection, training, cleaning, judgment and rejection form the real creative process; the generation button is only one node."),
    t("08｜产业化仍需要补上的部分\n长内容的技术表现仍低于创作者期待，尤其是跨镜头身份、空间连续、角色关系和世界观稳定。解决这些问题不能只等待更大模型，也需要分工、资产管理、版本控制、评价标准和新的制作管线。北影节 AIGC 单元试图搭建的正是这条从作品到产业的路径：让竞赛发现表达，让学术建立讨论，让技术解决瓶颈，让孵化和市场把创作推进到真实生产。","08 | What industrialisation still requires\nLong-form AI needs not only better models but also roles, asset management, versioning, evaluation and production pipelines.")
  ],
  N04:[
    t("01｜“设计已死”与近百万行代码\n张明华用两组相反的数据开场：2026 年前五个月，“设计已死”被宣布了 847 次；与此同时，他在 Code Work 中提交约 1200 次、80 万行代码，在 Code IDE 中提交约 170 次、17 万行代码。大部分代码由 Coding Agent 协助完成，但这些数字仍然说明，设计师的工作没有停留在 Figma、PRD 和评审意见，而是进入代码库、组件系统、提交记录、CI 和产品的长期维护。所谓 Design to Build，不是设计师换一种方式画图，而是参与产品被持续构建的现场。","01 | Design is dead, alongside nearly a million lines of code\nThe opening contrast shows design moving into repositories, component systems, CI and maintenance."),
    t("02｜Coding 变便宜，好 Code 没有自动变便宜\n分享区分了 coding 与 code。Coding 是把想法翻译成第一版可运行实现，AI 的确让页面、组件、状态和接口快速生成；Code 则指能进入真实产品、被长期维护的良好代码。第一版出现得快，并不会自动带来清晰架构，也不会让用户体验更容易做好。混乱代码库会让 Agent 消耗更多上下文和 Token，并继续生成外表可用、内部腐烂的系统。设计师学习工程知识的目的不是追求手写代码，而是理解什么结构能让体验长期成立。","02 | Cheap coding does not mean cheap good code\nFast first drafts do not create maintainable architecture or good experience automatically."),
    t("03｜设计系统进入真实构建链路\nCode Work 的设计系统是 monorepo 中可以运行的 workspace package，而不是只存在于 Figma 的 Library。业务模块消费组件、Token 与样式，设计侧可以在 Playground 中构建不绑定业务数据和 SDK 的交互版本，验证 UI、动效和状态。设计系统代码只占仓库约 6%，却构成用户眼睛看到、手能操作的几乎全部体验。进入代码库后，设计不再是一份工程实现之前的参考，而是产品运行时直接依赖的资产。","03 | The design system enters the real build chain\nA live workspace package lets business code consume design assets and lets designers verify behaviour in a real environment."),
    t("04｜第一层保障：Agent CMD 写清楚不可越过的边界\n高产能 Agent 很容易随手修改颜色、重写组件，微小偏差累积后会掏空设计系统。团队在项目根目录建立 Agent CMD，明确核心组件、Token 和变量是“设计圣域”，只有得到人类授权才能修改；任何业务 UI 必须优先消费已有组件；如果系统中缺少能力，应提示人评估是否扩展，而不是自行造轮子。它不是绝对权限，却把过去依赖口头提醒的原则放进每个人和 Agent 行动前都会读取的上下文。","04 | Layer one: Agent CMD\nExplicit repository rules protect core components and require consumption before creation."),
    t("05｜第二层保障：把走查规则变成 UI Check\n提示词是软约束，人会忘记也会绕过，所以第二层进入工程门禁。UI Check 读取 Design Token 与组件库，扫描业务 UI 是否硬编码颜色、引入 Agent 偏爱的通用图标库，或重复创建按钮、卡片与对话框。过去这些问题要靠设计师在评审中肉眼发现、反复沟通；现在可以先成为可运行检查器，再进入 pre-commit、PR 或 CI。它无法判断品味，却能挡住最常见、最危险的一致性漂移。","05 | Layer two: UI Check\nExecutable checks catch hard-coded colours, icon misuse and duplicated system components before review."),
    t("06｜第三层保障：让巡检 Agent 看协作过程\n代码符合设计系统，并不代表需求经过设计。第三层 Agent 会阅读提交、钉钉群聊、迭代评论、PRD 与知识库，识别哪些用户可感知的变化没有产品经理与设计师参与，随后在群中播报或询问责任人。Agent 产能太高，人不可能盯住每天所有变化；巡检把“任何交给用户的体验都应经过责任人判断”变成持续运行的协作机制。三层合在一起，设计发生在代码合入前、需求上线前和团队维护产品秩序的全过程。","06 | Layer three: a patrol agent\nCommits, chats and requirements are monitored for user-facing changes that bypass product and design review."),
    t("07｜Agent Loop：一个只能发声的囚徒如何行动\n为了说明 Build，张明华把模型比作只能发声的囚徒。模型本身无法改变现实，只能根据用户请求和已有上下文判断应调用哪个工具；read、edit、write、bash 等工具在外部执行，结果返回下一轮上下文，模型继续判断是否完成。Agent 产品因此不只是聊天框、Loading 和最终答案。设计需要决定模型能获得什么上下文、调用什么工具、何时确认、哪些过程暴露、结果如何检查，以及用户何时接管。","07 | Agent Loop\nA model acts only through tools, making context, permissions, visibility, checks and takeover central design questions."),
    t("08｜Design Agent 的完整工作顺序\nCode Work 把设计师流程翻译为 Agent 可执行的 Loop。第一步确认边界，用 Design System 工具形成颜色、字体、间距与组件状态；第二步写 Brief，明确为谁设计、目标和交互；第三步获取上下文，并保持用户请求、已批准设计系统和风格参考的优先级；第四步生成可点击、可继续修改的 HTML 或 React 工程；第五步检查占位文案、编造数据、默认蓝紫渐变、窄屏拥挤与表单可用性；第六步进入 Nudge 与 Frame，让用户轻推方向，并把画面区域连接到真实文件、组件和样式。","08 | The complete Design Agent sequence\nBoundaries, brief, prioritised context, editable artifact, quality checks, nudge and frame turn design method into an executable loop."),
    t("09｜Design 的新边界是对齐不确定性\nAgent 产品同时面对两端不确定性：用户常常说不清意图，并在制作中改变想法；模型也可能理解错、执行偏，或生成看似合理却未解决问题的结果。设计师不只是画输入框和美化输出，而是建立澄清、补足上下文、展示过程、评价和修正的机制。品味也从“亲手做得漂亮”扩展为识货能力：知道什么值得保留、什么必须舍弃，并把模糊批评转成 Checklist、Audit、Adapt 和 Polish 等可执行反馈循环。","09 | The new boundary is alignment under uncertainty\nDesigners create mechanisms for clarification, evaluation, correction, trust and human control."),
    t("10｜系统需要速度，也需要缓冲\nAI 可以快速产生大量代码和方案，但错误也会更快进入系统深处。好的产品不能只追求生成与上线速度，还要能评估、回滚，允许人在关键节点暂停讨论。Coding 是手段，最终目的仍是对产品体验负责。Build 变容易之后，真正稀缺的是知道为什么要做、怎样判断好坏，以及是否有勇气把系统推向更好的方向。","10 | Systems need speed and buffers\nEvaluation, rollback and human deliberation keep rapid generation from accelerating errors into the product.")
  ],
  N05:[
    t("01｜从历史看迁移，而不是预测一个确定未来\n杜海航明确说明，这场分享提出的是观察而不是结论，因为 AI-Native 仍在快速变化。他先回到数字体验史：个人电脑让 GUI 成为设计对象，浏览器与 WWW 让网页出现，Flash 扩展动态表达，智能手机带来 App，HTML5 与 WebGL 让实时交互和三维内容进入页面。设计师每个阶段能做什么，都与当时的技术底座紧密相关。理解今天的变化，也要把 AI 放进这条持续迁移的因果链。","01 | Read migration through history\nThe talk frames AI-native design as another shift in a long causal relationship between technical platforms and design practice."),
    t("02｜网页美学如何随媒介变化\n最早的网页只有超文本，后来网页三剑客、Flash 和素材图库建立了新的页面语言；Adobe 套件让插画、摄影和动效更容易组合；Sketch、Figma、Cinema 4D、Blender、Processing 与 WebGL 又把组件化、三维和代码图形带入设计。2014 至 2022 年，科技产品大量采用三维和实时渲染；生成式 AI 之后，页面中的内容更容易呈现艺术感、植物感和非传统建模的视觉。美学不是凭空流行，而是被可用工具和生产成本共同推动。","02 | How web aesthetics follow media\nHypertext, Flash, 3D, code graphics and generative imagery each expand what can become a mainstream visual language."),
    t("03｜工具并非替代，而是持续叠加\n杜海航强调这不是一张淘汰时间线。图库、Adobe、Figma、Blender 与代码仍然存在，Midjourney、GPT、通义万相和 AI Coding 工具叠加在它们之上。Code Work、Codex 或类似工具看似属于开发者，但在今天也可以成为设计工具，因为设计师通过它们直接生产组件、原型和真实界面。变化的关键不是所有人转行写代码，而是设计表达可更直接地进入运行环境。","03 | Tools accumulate rather than simply replace one another\nAI coding joins existing visual and prototyping tools as a medium for producing real components and interfaces."),
    t("04｜Organic Intelligence：新设计语言怎样产生\n千问云尝试用代码与 AI 定义一套名为 Organic Intelligence 的设计语言。相较传统科技产品常见的机械、冷峻和几何感，它更强调植物感、有机变化和艺术内容。这套语言不只是一组视觉效果，而要落实到组件、Token、字体梯度、动效和内容生成方式。AI 让视觉素材更容易获得，也迫使团队把风格进一步整理为能够被系统稳定调用的资产。","04 | Organic Intelligence\nA more organic visual language becomes a coded system of components, tokens, typography, motion and generated content."),
    t("05｜为什么千问云强调“人机平权”\n千问云是面向开发者和 Agent 的 API 平台，用户不再只有人。Agent 需要比较模型、理解产品、购买服务并进入控制台完成操作。传统网站通常把机器视为读取文本的爬虫，但 Agent 必须操控界面。设计因此要同时考虑 Human Read 与 Agent Read：一个组件既要让人快速理解，也要通过语义、结构和代码让 Agent 知道它是什么、能做什么、下一步如何执行。","05 | Why Qwen Cloud pursues human–agent parity\nThe site must support agents that compare, purchase and operate services, not merely read text."),
    t("06｜设计资产从说明图变成 Code Block\n传统设计系统会定义原子组件、信息架构、交互原则和任务流程，交给前端开发实现。Agent 参与后，所有组件都必须 accessible from code。设计体系的重要资产变成 Code Block、Design.md、命令行 Skill、Token 与可执行组件。千问云的规范最终可以抽象为一行命令，让鸿蒙或 Web Coding 项目调用同一套调性。规范不再只告诉别人应该怎么做，而是直接参与生成。","06 | Design assets become executable code blocks\nComponents, tokens, Design.md, commands and skills move from documentation into the production mechanism itself."),
    t("07｜可交互产品表达同时服务人和 Agent\n过去 Banner、GIF 和视频被嵌入页面，用来向人展示产品能力。千问云把演示做成代码组件：例如用户点击 Coder 的模拟编辑器，可以直接理解它如何工作；Agent 则能从代码和语义识别这个组件代表的产品、状态与动作。代码化也让深浅色适配、响应式和轻量交互由同一资产承担，不必重复制作两份静态材料。","07 | Interactive product expression serves both people and agents\nCoded demonstrations communicate product behaviour through direct interaction and machine-readable semantics."),
    t("08｜设计师怎样参与代码生产\n团队设计师在 AI 辅助下贡献超过二十万行代码，其中大部分不是手工逐行编写。这个数字的意义不是证明设计师应成为传统工程师，而是说明代码生成降低了进入门槛，设计师可以直接参与组件、规范和体验原型。过去他们画出按钮所有状态并等待实现；今天可以通过 Principle、原子组件和 Code Block 直接构建实时可用的版本，再与工程共同维护。","08 | How designers participate in code production\nAI assistance lets designers contribute directly to components and runtime prototypes without redefining themselves as traditional engineers."),
    t("09｜Design in Runtime：交付物从图纸变成运行中的体验\n分享最后对比两种工作方式：一种是在画布中穷举页面、跳转和组件状态；另一种是用代码定义原则、资产和交互，让平台在运行环境中直接呈现。杜海航将这种迁移概括为 Design in Runtime。未来数字体验的设计交付物不再只是一张画出来的图，而是可以实时操作、点击、验证和继续修改的系统。它不意味着视觉判断消失，而是视觉、交互和工程第一次更紧密地存在于同一产物中。","09 | Design in Runtime\nThe deliverable becomes an operable, testable and modifiable system where visual, interaction and engineering decisions coexist.")
  ],
  N06:[
    t("01｜一个角色从纸面到产品，为什么曾经需要半年\n罗杰瀚从两岁开始画画，拥有近五十年的创作经验。他先讲自己过去做联名潮玩的流程：纸面角色要经过建模、材料选择、比例调整、样品制作和工厂沟通。早期甚至由师傅用泥一点点塑形，后来 3D 建模节省了时间，但一个角色从概念到量产方案仍可能耗时半年，并需要艺术家、建模、产品与工厂共同完成。AI 对他最直接的冲击，正是这条漫长链路开始被重新组织。","01 | Why a character once took six months\nTraditional designer-toy production links drawing, modelling, materials, proportion, prototyping and factory coordination."),
    t("02｜第一次对话：Agent 没有直接出图，而是开始提问\n他把一张旧画上传到妙鸭，原本以为系统会直接生成一个潮玩，结果 Agent 先问希望怎样推进、是否满意、倾向什么设计风格。这种交流让他想到过去与工厂厂长和师傅反复讨论的过程。系统并不是只给一张最终图，而是在每轮反馈中调整角色设定、表情、动作和风格。对于长期依赖对话推进产品的艺术家来说，AI 的价值首先是把协作过程带到个人可以持续控制的界面中。","02 | The agent begins by asking questions\nIterative dialogue resembles the artist’s former collaboration with factory specialists rather than one-shot image generation."),
    t("03｜从主图延展到一整套产品语言\n对话继续后，系统不仅生成角色主视觉，还展开表情、动作、漫画、盲盒、毛绒和 3D 材质效果。过去每一种延展都可能需要新的沟通和执行岗位，现在它们可以围绕同一角色设定连续产生。关键并不是数量，而是一致性：艺术家能在看到产品化效果后反过来判断角色比例、气质和材质是否仍符合原始想象。","03 | From key art to a complete product language\nExpressions, poses, comics, blind-box, plush and material studies remain connected to one evolving character definition."),
    t("04｜细节修改比一次生成更接近真实设计\n潮玩最磨人的往往不是大方向，而是头发、水渍、衣服纹理、眼神、手势和体态。传统流程中，局部问题可能导致重新建模，或需要在 Photoshop 中一点点框选修改。妙鸭的局部编辑允许艺术家只选中不满意的区域，用语言说明变化，并保持其他部分稳定。罗杰瀚认为“好的设计都是细节调出来的”，因此这种持续、局部、可回退的能力，比一次生成看似完整的图片更重要。","04 | Local iteration is closer to real design\nSelective editing preserves the whole while refining the small decisions that give a character its soul."),
    t("05｜从旧手稿到文字创造新角色\n使用一段时间后，他不再只把过去的画转换成潮玩，而是尝试完全不用参考图，用文字描述一个穿橙色宇航服、蓝紫头发的新角色。第一版与脑中形象有距离，但他像过去修改草图一样继续对话：调整颜色、体态、表情和感觉。过去可能要画十几张甚至三五十张探索稿，现在这些探索在连续对话中快速展开，同时 Agent 也会提出艺术家原本没有想到的方案。","05 | From old drawings to new characters through language\nText dialogue supports rapid exploration while still relying on the artist’s iterative judgment."),
    t("06｜版权记录为什么属于创作流程\n艺术家使用生成工具时，一个重要顾虑是过程和作品归属。妙鸭记录每一步调整，让方案演化有迹可循。对潮玩这种最终会进入商品、联名和授权的创作而言，过程存证不是附加功能，而是产品化的前提之一。最终交付也不是孤立图片，而是主图、三视图、表情包、动作、漫画与不同材质效果组成的完整设计包。","06 | Provenance belongs inside the workflow\nRecorded steps and a complete design package address the realities of licensing, collaboration and production."),
    t("07｜AI 没有替代审美，而是缩短审美抵达产品的距离\n罗杰瀚一开始也对 AI 感到恐惧，但实际使用后，他看到的不是艺术家被取代，而是一个人可以完成过去需要团队和数月才能推进的前期工作。创作者不必先成为建模或工程专家，可以把长期积累的角色经验、审美和想象交给 AI 搭档，再通过判断与细节调整保持作品属于自己。技术缩短的是审美到产品之间的生产距离，而不是审美本身。","07 | AI shortens the distance from judgment to product\nThe artist’s accumulated taste remains central while the partner reduces modelling and coordination barriers.")
  ]
};
talks.forEach(x=>{if(morningLongform[x.id])x.core=morningLongform[x.id]});

const afternoonLongform:Record<string,Text[]>={
  V01:[
    t("01｜从 AI Coding 的普及说起\n杨涛先回顾团队过去三年从 AIGC 到 Agentic AI 的探索。最明显的变化是，AI Coding 不再只是程序员的独门工具，而逐渐成为通识创造能力。团队中有设计师因为现有工具无法高效修改页面要素，便自己做了工具、写说明并发布到 npm，两天获得一百多次下载。这个例子说明设计师与技术的关系正在变化：不再只是等待更好的软件，也可以把具体问题变成可供他人使用的工具。","01 | AI coding becomes a general creative capability\nDesigners move from using tools to building and sharing tools for their own problems."),
    t("02｜Vibe Designing 的起点不是像素\n传统界面工作从像素、图层和栅格等执行末端开始，Vibe Designing 则要求设计师先说清楚“我要什么体验、什么调性”。Vibe 并不是一句模糊的感觉，而是需要继续翻译成模型能理解的意图、上下文和规则。设计师的工作因此从绘制确定结果，上移到定义系统应如何理解需求、怎样产生方案，以及怎样判断方案有没有偏离。","02 | Vibe Designing starts before pixels\nDesigners define experience, tone, context and evaluation before generating interfaces."),
    t("03｜设计实时组织的界面\n在 Agent 产品中，体验会随着用户意图实时组织，界面不一定预先存在。过去设计师梳理固定信息架构和页面流程，今天还要定义生成式 UI 的规则：什么信息应该出现、什么状态应被隐藏、何时需要用户确认，以及系统如何根据变化继续组织下一步。界面可以是临时的，但支撑它的体验原则、组件语义和交互边界必须稳定。","03 | Interfaces are organised in real time\nGenerated UI changes with user intent, while its underlying principles and boundaries remain stable."),
    t("04｜从 Human Only 到 Human and AI\n当 Agent 开始阅读并操作产品，设计系统不能只服务人。组件、Token、信息架构、可访问代码、Design.md 和场景模式需要同时让人理解，也让模型调用。杨涛把这个变化拆成三个层级：原子层包含品牌、媒体和基础组件；范式层包含布局、风格、信息架构和交互原则；机制层则描述组件组合、结构和用户行为。人看见的是体验，Agent 读取的是可执行结构，两者需要在同一系统中对齐。","04 | From human-only to human-and-AI design systems\nAtomic assets, paradigms and mechanisms must be readable and executable by both people and agents."),
    t("05｜意图—生成—对齐的工作流\nVibe Designing 不是让模型一次生成最终页面。设计师先提供品牌和设计语言，再组织用户请求、业务资料与风格参考；模型产生多个方向后，设计师通过判断选择并继续修改。生成只是中间步骤，对齐才是主要工作：把模糊意图变成结构化要求，让系统解释自己的行动，并用反馈把结果拉回正确方向。","05 | Intent, generation and alignment\nGeneration is only the middle of a workflow that structures intention and repeatedly aligns results."),
    t("06｜作品集为什么会从 PDF 迁移到网站\n杨涛最后把变化落到设计师的个人表达。设计师依然“用作品说话”，但作品不再只是静态 PDF。一个动态网站可以承载文化理解、叙事、交互、视觉品味和使用 AI 的能力，也让观看者直接体验设计是否成立。作品集媒介的变化并非追赶形式，而是因为设计交付本身正在从描述结果，迁移到可运行、可交互和可继续迭代的系统。","06 | Why portfolios move from PDF to websites\nA running site demonstrates narrative, interaction, taste and AI capability in the medium of the new deliverable itself.")
  ],
  V02:[
    t("01｜设计是一门翻译的手艺\n王婉从政企与行业项目出发，把体验设计定义为翻译：AI 时代不缺模型和工具，真正困难的是把技术能力翻译成行业能够理解、采用并产生价值的解决方案。设计师需要同时理解技术语言、业务目标、专业流程和真实用户，再把这些信息重新组织为产品体验。这不是把复杂内容做得好看，而是判断哪些关系必须保留、哪些概念需要解释、怎样让方案进入实际工作。","01 | Design is the craft of translation\nThe designer connects technical capability, industry language, business goals and real workflows."),
    t("02｜从接需求到定义方案\n在复杂行业中，需求通常以专业术语、既有流程或局部问题出现。如果设计师只负责接收和呈现，很容易把旧流程换成新界面，却没有改变问题。分享强调从“接需求的人”转向“定义方案的人”：先理解行业如何运作、决策由谁完成、数据在哪里产生、哪些环节最易出错，再决定 AI 应进入哪一步。设计的翻译力因此包含问题重述与机会定义，而不只是交付表现。","02 | From receiving requests to defining solutions\nDesigners restate the problem, map decisions and locate where AI should enter the workflow."),
    t("03｜行业知识如何变成 AI 可以使用的结构\n千行百业中的经验常散落在专家、文档和项目过程里，模型并不会因为接入资料就自动理解。团队需要把术语、规则、案例、角色和判断条件结构化，让 AI 知道什么信息优先、什么结果不可接受。设计师在这里承担知识架构工作：把隐性经验转成可检索、可组合、可验证的资产，同时保留具体场景，避免知识被压缩成空泛结论。","03 | Structuring industry knowledge for AI\nTerms, rules, cases, roles and judgment criteria must become retrievable and verifiable assets."),
    t("04｜优秀项目库不是灵感图片库\n分享中的项目沉淀工具给现场留下了深刻印象。真正有用的参考库不只保存最终页面，还应保留问题背景、策略、实施方法、约束、结果与复盘。设计师搜索时得到的不是一个可模仿样式，而是一套曾经如何解决相似问题的路径。语义检索降低了寻找参考的时间，也让组织不会在人员变化后反复丢失经验。","04 | A project library is not a moodboard\nUseful references preserve problem, strategy, constraints, method, outcome and review rather than screenshots alone."),
    t("05｜从个人参考习惯到组织知识能力\n当项目被结构化沉淀，参考行为也发生变化。设计师不必每次从公开网络重新寻找视觉案例，而能从组织历史中发现相似业务、复用成熟判断，并识别旧方案不适用的新条件。知识库的价值不只在效率，也在让设计决策有依据、可追溯，并支持团队在已有认知上继续前进。","05 | From personal references to organisational capability\nStructured archives make decisions traceable and allow teams to build on prior reasoning rather than restart research."),
    t("06｜翻译力最终要回到业务结果\nAI 方案是否成立，不能只由模型指标或界面完成度判断。它需要在行业流程中减少理解成本、帮助角色协作，并对真实决策产生影响。设计师的不可替代性并非来自掌握更多术语，而是能在不同专业之间建立准确关系，把技术可能性转化为人可以信任和使用的产品。","06 | Translation must return to business outcomes\nA successful AI solution reduces friction, supports collaboration and earns trust inside the real industry process.")
  ],
  V03:[
    t("01｜书法并不是静止的传统\n沈乐平先沿书法史说明，传统从未停在一个固定样式。甲骨、金文保留象形关系；秦统一文字，汉代隶变推动古文字进入新的符号系统；魏晋尚韵、唐代法度、宋人尚意与清代碑学，又分别回应不同社会、思想和审美。近现代书法继续受到现代主义、全球化和当代艺术影响。AI 不是第一次改变书法的外部条件，它进入的是一条不断突破边界、再形成新范式的历史。","01 | Calligraphy is not a static tradition\nIts forms have continuously changed with writing systems, society, aesthetics and artistic thought."),
    t("02｜AI 为什么难以理解传统审美\n让模型生成像毛笔字的图并不困难，真正难的是分辨长与变、雅与俗、行与质、正与奇，并理解气、韵、法、意境等含义并不精确的概念。传统美学常用“水”“气”“天”等关系性语言表达感受，无法简单对应成单一标签。如果训练只追求形似，模型可能生成结构正确却文化判断错误的结果。专业审美必须进入数据、训练和评价过程。","02 | Why traditional aesthetics are hard for AI\nNuanced concepts such as rhythm, character and negative space resist simple labels and visual imitation."),
    t("03｜“未未书”工作坊如何开始\n中国美术学院书法学院与阿里云设计中心共同发起工作坊，从北魏墓志、智永《千字文》、草书、颜真卿等经典范本采集高清数据。选择这些材料不是为了建立一个万能书法模型，而是让不同历史风格保持清晰来源。训练不仅处理笔画外形，也尝试让模型建立风格意识，理解一套书写方式内部的结构、节奏和取法关系。","03 | How the workshop began\nHigh-resolution data from distinct canonical works preserves provenance and supports style-aware rather than generic generation."),
    t("04｜风格杂糅与传统取法\n书法学习常讲“入古出新”：先深入临摹多个传统，再形成个人取舍。工作坊的风格杂糅实验模拟这种路径，让模型以一种范本为主、另一种为辅，观察笔法、结构与章法怎样重组。实验的意义不在生成奇观，而在把传统学习中的隐性方法显性化，进而讨论算法如何参与审美而不抹平差异。","04 | Style blending as a model of traditional learning\nExperiments simulate taking one source as primary and another as secondary, making implicit learning paths explicit."),
    t("05｜篆刻：从数据采集到刀法与虚实\n篆刻实验从数千方古代汉印中采集数据，建立训练、生成与风格迁移闭环。模型需要处理文字、章法和残破，还要接近冲刀、切刀的痕迹，以及“计白当黑、虚实相生”的空间语言。即便生成已经足以乱真，沈乐平仍强调最终判断属于专业创作者：视觉相似只是起点，作品是否符合篆刻的文化和审美内核，需要人来甄别。","05 | Seal carving from data to cutting and negative space\nThe model addresses composition, erosion and knife traces, while professional judgment remains responsible for cultural validity."),
    t("06｜AI 是器，人是魂\n分享明确区分主客：AI 擅长运算、数据处理和模型生成，是“器”也是“客”；师生、艺术家与研究者是主体，负责气韵、心性、意境、生命体感和审美标准。AI 可以帮助创作者更快进入经典、比较风格并获得新的材料，但探索未知、决定表达和承担文化责任仍是人的工作。技术不是替代艺术家，而是要求艺术家更清楚自己的判断从何而来。","06 | AI is the instrument; the human is the creative subject\nComputation supports access and exploration, while people retain judgment, expression and cultural responsibility."),
    t("07｜数字版权与作品身份\n人机共创使“谁的作品”变得复杂。工作坊借鉴书法中的年份、落款和印章，建立版数编号、存证日期与数字身份，探索具备数字版权的人机共创作品。这个制度实验与视觉实验同样重要：技术进入传统艺术后，创作、理论、教学、展陈和资产机制需要同时更新，而不是只增加一种新图像。","07 | Digital copyright and work identity\nEdition numbers, dates and digital identity extend traditional provenance into human–AI co-creation."),
    t("08｜真正的传承是创造能创造的人\n沈乐平最后把教育目标从生产作品转向培养主体。高校中的人机合作，不应只教学生生成某种风格，而要让他们贯通古今中外，保持判断力、感受力，并拥有整合知识与技术的能力。真正的文化创造是“创造能创造的人”；传统能够延续，也不是因为它拒绝变化，而是每一代人以新的工具重新理解它。","08 | True inheritance creates people who can create\nEducation should develop judgment, sensitivity and integrative capacity rather than teach one generated style.")
  ],
  V04:[
    t("01｜从社区观察设计角色变化\nAJ 不是设计师出身，而是产品经理和 WaytoAGI 社区发起人。他从大量创作者实践中看到，AI 并没有单纯减轻负担：设计师开始写代码、定义设计语言、写 Prompt、理解组件与商业流程，越来越像一个全干工程师。分享围绕三个问题展开：怎样让风格成为资产，怎样让内容结构化，以及一个 Demo 怎样真正进入市场。","01 | Observing changing design roles through a creator community\nAI expands responsibility toward code, design language, content structure and business."),
    t("02｜Design.md：把风格从感觉变成资产\nAJ 会从网站中抽离品牌、颜色、字体、组件和视觉规律，形成 Design.md。它不是简单的截图收藏，而是模型可以理解的风格说明书。下一次生成页面时，同一套规则可以被继续调用。风格由一次性表达变成可复用资产，也让个人与小团队不必每次重新解释自己的视觉方向。","02 | Design.md turns style into a reusable asset\nBrand, colour, typography and component rules become model-readable and repeatable."),
    t("03｜内容结构化与个人知识库\n录音、笔记、网页收藏和对话灵感只有进入结构，才能成为生成时有效的上下文。AJ 把长期网络浏览与社区经验沉淀进知识库，按主题检索，再与 Design.md 一起交给模型。网页式演示本身也是由这些上下文对话生成。个人知识库的目标不是囤积信息，而是让过去的判断能够在下一次任务中被调用。","03 | Structured content and personal knowledge\nRecordings, notes and references become retrievable context rather than an inert archive."),
    t("04｜把自己变成可调用的系统\n分享进一步讨论数字分身：把个人常用的判断、表达方式和工作流程整理为模型可以调用的能力。它不意味着复制一个人的全部，而是将重复劳动、资料搜集和初步组织交给系统，让本人把精力放在方向与最终品控。设计资产、内容资产和流程资产组合后，个人能力才可能被稳定放大。","04 | Turning personal practice into a callable system\nJudgment patterns, expression and workflow become reusable capabilities while the person retains direction and quality control."),
    t("05｜Demo 与市场之间仍有很长距离\nAI 可以快速生成网页和代码，但 Demo 不是产品。进入市场仍需要明确用户、建立产品流程、验证需求、处理交付和持续运营。AJ 强调 OPC 不是一个人硬做所有岗位，而是个人作为系统指挥者，让 AI 和外部能力承担大量执行，并由自己连接创意、产品与商业结果。","05 | A demo is not a market-ready product\nOPC is system orchestration across users, validation, delivery and operations rather than solitary execution."),
    t("06｜从漂亮页面到商业结果\nAI 时代的设计价值从页面美观扩展到审美资产、流程和商业结果。以前验证一个想法需要产品、开发和测试团队，现在一个人可以更快启动，但机会也更依赖执行：能否持续迭代、找到用户并把资产沉淀下来。技术降低了起跑成本，却没有替代进入市场的判断与行动。","06 | From attractive pages to commercial outcomes\nAI lowers startup cost, but execution, users, iteration and asset accumulation still determine value.")
  ],
  V05:[
    t("01｜从国家级纪录片到 AI 短视频\n抽象仔曾参与《航拍中国》《祖国八百年》等央视项目，后来转向 AI 内容创作。这个转变不是因为传统制作失去价值，而是 AI 改变了从想法到影像的组织方式。分享以真实商业项目为主线，展示自动化增加后，创作者的主要工作如何从生产每一帧，迁移到设定方向、选择素材和维持作品一致性。","01 | From documentary production to AI content\nThe talk traces a shift from frame production toward direction, selection and consistency."),
    t("02｜流量案例与版权警醒\n团队将海外狗血故事放进包青天式的宋代美学，并配合国民歌曲，获得海外主播和媒体大量传播。流量也带来版权争议，让团队意识到 AI 创作不能只追求速度与话题。项目的传播最终促成与王力宏合作 MV，但进入更高要求的商业项目后，审美、版权、流程和客户信任都需要被重新建立。","02 | Viral success and copyright warning\nA widely shared experiment created opportunity while exposing the limits of speed-first AI creation."),
    t("03｜四分钟 MV 的真实成本\nMV 由十人团队历时近三个月完成，生成约五千条可用素材，并消耗约六十万点模型积分。一个关键出场镜头尝试约五百次，单镜头便消耗大量资源。数字说明 AI 并不是按下按钮就完成影片：生成让候选数量爆炸，创作者反而需要更强的筛选、版本管理与统一能力。","03 | The real cost of a four-minute music video\nA ten-person, three-month process with thousands of assets shows that generation shifts work into selection and control."),
    t("04｜先确定人物，再建立场景世界\n团队首先围绕艺人要求建立四视图，确定面部、伤痕、服装与角色气质；人物设定稳定后，再围绕它设计环境和镜头。为了避免古代场景中石头排列过度整齐的“AI 感”，他们购买真实商业照片作为约束，再让模型润色。真实性并不来自模型默认，而来自参考选择与对不自然细节的识别。","04 | Stabilise the character before building the world\nTurnarounds, styling and real photographic references constrain identity and scene realism."),
    t("05｜新的团队矩阵\n项目重新划分角色：艺术概念师把客户想法变成风格画面；人物设定师与造型师维持角色；场景设计师负责空间与真实感；团队成员又共同成为 AI 生成导演，大量生产并选择素材。AI 没有消除团队，而是改变了专业边界。执行可以并行扩张，但艺术方向必须由统一判断串联。","05 | A new team matrix\nConcept, character, styling, environment and generation direction replace a simpler linear production chain."),
    t("06｜从生产逻辑到决策逻辑\n当素材生成越来越自动化，稀缺性从“能不能做出来”转向“留下哪一个”。创作者必须判断哪个镜头符合人物、音乐和叙事，哪些看似精彩却破坏整体。商业项目还要处理客户沟通、每日推进和期待管理。AI 时代的审美并非只选漂亮画面，而是在海量可能中持续作出一致选择。","06 | From production logic to decision logic\nAs execution becomes abundant, value concentrates in coherent selection, client alignment and artistic direction.")
  ],
  V06:[
    t("01｜从 3D 生成产品到世界模型公司\n朱瓜瓜先介绍 VAST / Tripo 的业务：公司以 AI 3D 大模型和世界模型进行算法研究与产品落地，已有大量全球创作者生成近亿级 3D 模型。图片到模型的速度提升只是表面变化，更深的问题是当资产生产门槛大幅下降，品牌视觉团队、产品流程和设计负责人该如何重新组织整条 Pipeline。","01 | From 3D generation to world models\nThe talk asks how near-instant asset generation changes teams, products and the entire pipeline."),
    t("02｜Vibe 只能启动，Pipeline 才能生产\n灵感可以用自然语言和参考图迅速表达，但一次 Vibe 不能保证模型拓扑、材质、风格和品牌一致性。真正进入生产，需要明确输入标准、生成步骤、选择规则、后处理、版本与复用方式。分享因此把重点从“能生成 3D”转向“怎样让生成结果可生产、可复用、可规模化”。","02 | Vibe starts the process; pipeline makes it productive\nProduction needs standards, selection, post-processing, versioning and reuse beyond initial generation."),
    t("03｜AI Native 品牌视觉团队怎样工作\n传统品牌团队按平面、三维、动效和制作岗位分工，AI 让这些边界变得可穿透。团队可以更快探索角色、材质、场景和传播内容，但必须共享同一套风格资产与质量标准。设计师的任务从完成一个画面，扩展为维护一套能够不断产生品牌内容的系统。","03 | How an AI-native brand team works\nFaster cross-medium exploration requires shared style assets and quality standards rather than isolated outputs."),
    t("04｜从对象生成到场景与关系\n3D 能力正在从单个角色、商品和道具，扩展到完整场景。世界模型关注的不只是画面，而是空间结构、对象关系、物理规则与可交互性。对游戏、影视、潮玩和空间设计来说，这意味着原型不再只是看上去成立，还要能够进入后续编辑、动画和交互。","04 | From object generation to scenes and relations\nWorld models extend 3D creation toward spatial structure, object relations, rules and interaction."),
    t("05｜为什么设计负责人会变成 Pipeline Director\n当生成执行分散到不同成员与 Agent，Art Director 只给视觉方向已经不足。负责人还要设计流程：哪些资产进入模型、怎样命名与存储、哪些步骤自动化、何时由人判断、结果如何回到品牌系统。Pipeline Director 不是减少审美，而是让审美通过流程稳定作用于大规模生产。","05 | The rise of the Pipeline Director\nLeadership expands from visual direction into assets, automation, human checkpoints and system feedback."),
    t("06｜规模化不等于平均化\nAI 让大量生产成为可能，也容易让品牌视觉被模型默认风格稀释。可规模化的前提是核心资产、风格边界和评价机制足够清晰，使每次生成都能保留品牌差异。未来竞争不只在模型速度，而在谁能把模型组织成可靠的创意与生产系统。","06 | Scale must not become averaging\nClear assets, boundaries and evaluation keep mass generation from dissolving brand distinctiveness.")
  ],
  V07:[
    t("01｜AI 对下一代不是新工具，而是创作环境\n吕思彤 13 岁，是独立开发者和资深 AI 用户。她把分享分为热爱 AI 的原因、成长与收获、作品展示和开发思路。与成年人先学习传统流程、再把 AI 加入工具链不同，她从开始创作时就把模型、代码和 Agent 视为自然环境。这种差异让现场看到，所谓 AI 原住民不是更早学会提示词，而是没有预设“什么工作必须由某个职业完成”。","01 | AI is a creative environment for the next generation\nAn AI native begins with models, code and agents as ordinary parts of making rather than later additions."),
    t("02｜超过四千小时与近百件作品\n她的成长并非一次灵感带来的天才故事，而是长期投入。超过四千小时的学习和实践、近百件作品，构成从好奇到独立开发的路径。每个项目都带来新的问题：怎样让功能运行、怎样让别人使用、怎样修正错误。AI 降低了开始的门槛，却没有替代持续行动。作品数量背后真正值得关注的是反复完成从想法到结果的循环。","02 | Over 4,000 hours and nearly 100 works\nLow entry barriers do not replace the sustained practice of moving from idea to working result."),
    t("03｜成长发生在真实项目中\n她不是先学完一套完整课程再开始，而是在具体目标中补充需要的知识。遇到模型无法完成的部分，就理解代码、接口或产品逻辑；看到结果与设想不同，就继续调整。项目成为学习结构，AI 则承担解释、协作和执行。对设计教育而言，这提示了一种变化：课程可以从教授固定软件，转向帮助学生提出问题、验证方案并理解系统。","03 | Growth happens inside real projects\nProjects structure learning, while AI supports explanation, collaboration and execution."),
    t("04｜作品不只证明技术，也表达个人兴趣\n作品展示覆盖不同方向，反映她如何把个人兴趣迅速变成可运行原型。对年轻创作者而言，AI 最大的吸引力不是效率指标，而是一个想法不必等待成年、组队或获得完整资源才能被尝试。原型让她更快看到问题，也更快决定是否继续。创作与反馈之间的距离被缩短。","04 | Work expresses interests, not just technical ability\nFast prototypes let young creators test ideas before having a team, formal role or complete resources."),
    t("05｜她怎样组织智能体与开发\n分享中的开发思路强调把任务拆开：先说明目标，再让智能体协助研究、生成和检查，遇到问题继续提供上下文。她并不把 AI 当作永远正确的答案，而是在反复对话中推进。一个十三岁的开发者能够完成复杂项目，说明 Agent 正在成为新的认知脚手架，但最后仍需要人判断需求、选择方向和确认结果。","05 | How she organises agents and development\nGoal-setting, task breakdown, context and repeated checking make the agent a cognitive scaffold rather than an oracle."),
    t("06｜从个人故事看到教育与团队的变化\n这场分享的价值不在于要求所有人复制她的成长速度，而是让团队观察下一代会怎样理解专业边界。他们可能同时是设计者、开发者、产品经理和内容创作者，并通过作品学习。未来团队需要接住这种跨界能力：既保护好奇心和行动，也帮助年轻创作者建立审美、伦理、验证和长期维护意识。","06 | What the story means for education and teams\nFuture teams must support cross-disciplinary making while developing judgment, ethics, verification and maintenance.")
  ],
  V08:[
    t("01｜先澄清 OPC 不是自由职业者的新名字\n刘飞主持圆桌，与 AJ、抽象仔讨论 AI 时代的一人公司。OPC 的核心并不是一个人承担设计、开发、销售和运营的全部劳动，而是一个人能够搭建由模型、Agent、工具、外部服务和合作伙伴组成的系统。个人负责方向、资源编排和最终结果，执行工作可以由不同能力完成。它与传统自由职业的差别，在于是否形成了能够持续运行和放大的组织机制。","01 | OPC is not simply a new name for freelancing\nOne person orchestrates models, agents, services and collaborators into a repeatable system."),
    t("02｜为什么现在 OPC 变得可操作\n过去把想法变成产品，需要找到设计、开发、测试和运营；现在个人可以更快完成原型、内容和发布，沟通与启动成本显著下降。圆桌并没有把它描述成轻松创业：低门槛也意味着更多人同时进入，想法和 Demo 更容易同质化。真正的机会来自能否选择具体问题、迅速验证，并持续把结果推进到用户。","02 | Why OPC becomes operational now\nLower coordination cost enables fast prototypes, but also increases competition and sameness."),
    t("03｜这个时代更看执行力\n当模型能把大多数想法变成看得见的结果，“我有一个创意”不再稀缺。圆桌反复强调执行：是否愿意把第一版交给真实用户，是否能接受反馈、继续修改，是否能处理产品之外的交付和商业问题。AI 扩大个人行动半径，但不会替代行动本身。很多机会并不是输在方案不聪明，而是停留在演示阶段。","03 | Execution becomes more valuable than isolated ideas\nThe differentiator is moving beyond demos into users, feedback, delivery and business."),
    t("04｜通用产品更难，具体产品更有机会\n讨论提出，面向所有人的统一产品越来越难做。模型能力趋同后，个人公司更适合围绕明确人群和场景，提供模块化、定制化或带有个人判断的产品。与大公司比规模不是优势，理解细分用户、快速调整和形成独特表达，才是 OPC 可以利用的结构性特点。","04 | Specific products may outperform universal ones\nOPCs can compete through narrow audiences, modular solutions, speed and distinct judgment rather than scale."),
    t("05｜审美如何进入商业逻辑\n抽象仔的创作实践说明，审美并非商业之后的包装。选什么题材、怎样建立风格、如何面对客户、哪些结果可以交付，都会影响成本和传播。AJ 则把审美整理成 Design.md、知识库和流程资产。圆桌中的共同点是：个人表达只有被转化为稳定方法和可识别产品，才可能持续产生商业价值。","05 | How aesthetics enters business logic\nChoice, style, client alignment and reusable design assets shape both production cost and market identity."),
    t("06｜建立自己的资产，而不是每次归零\n圆桌最后落到资产沉淀。风格、知识、内容、用户关系、工作流、工具和案例都应在项目结束后留下来，并进入下一次创作。没有资产积累，AI 只会让个人更快完成一次性劳动；有了结构化资产，系统才会随着实践变强。OPC 的长期价值不在一个人做得多快，而在每次行动是否让下一次更有基础。","06 | Build assets instead of resetting after every project\nStyle, knowledge, audience, workflow and cases must compound across projects for an OPC to become durable.")
  ]
};
talks.forEach(x=>{if(afternoonLongform[x.id])x.core=afternoonLongform[x.id]});

Object.assign(talks.find(x=>x.id==="V00")!,{core:[
  t("01｜王路平：Vibe Designing 要回应什么问题\n王路平从现场观察到的几个变化切入。AI 设计已经不只发生在平面、海报和 UI，创作者开始进入内容、产品、3D 与个人公司等更完整的链路。对阿里云设计中心而言，Vibe Designing 需要回答的不是“还能生成什么”，而是设计怎样在这些新领域继续发挥作用：如何让技术结果产生审美与品味的共鸣，如何把个人的创造冲动推进为可体验的产品，以及设计师怎样在新的生产关系中保持判断。","01 | Wang Luping: what Vibe Designing must address\nThe opening asks how design can create aesthetic resonance and move creative intent into products across content, 3D and new organisational forms."),
  t("02｜王路平：审美与品味为何重新成为问题\n他提到自己反复观看一支用 Kanye West 形象演唱《新鸳鸯蝴蝶梦》的 AI 视频。吸引他的并不只是技术反差，而是视频能在特定情绪下产生变化和共鸣。这个例子让他把问题落到设计师熟悉但难以量化的部分：当生成能力越来越普遍，作品为什么让人愿意反复观看？Vibe Designing 如果只解决生成效率是不够的，还需要进入审美、品味和情绪关系。","02 | Wang Luping: why aesthetics and taste return\nA repeatedly watched AI music video becomes an example of emotional and aesthetic resonance beyond technical novelty."),
  t("03｜王路平：从成熟的二维生成走向 3D\n在平面、海报和界面领域，AI 已经相对成熟，但 3D 仍有大量尚未完成的工作。对象生成、材质、空间关系、场景和世界模型，会进一步改变潮玩、游戏、影视和品牌内容的生产方式。因此本场安排了 AI 3D 团队分享，不只是展示更快的建模，而是讨论整条设计流水线是否需要重构，以及未来的设计负责人如何同时管理审美方向与生产 Pipeline。","03 | Wang Luping: moving from mature 2D generation into 3D\nThe 3D discussion concerns objects, materials, scenes, world models and the redesign of production pipelines."),
  t("04｜王路平：AI 原住民带来的反向学习\n他特别介绍了全场年龄最小的分享嘉宾。看到十几岁的孩子在 AI 比赛和产品开发中取得成果后，他意识到“AI Native”不仅是技术术语，也可以描述从小就在 AI 环境中创作的人。成年人通常把 AI 加入已有流程，年轻创作者则可能没有固定的职业和工具边界。邀请吕思彤分享，是希望从下一代的使用方式中反向理解设计、代码与产品将怎样融合。","04 | Wang Luping: learning from AI natives\nYoung creators who begin inside an AI environment reveal different assumptions about design, code and products."),
  t("05｜王路平：个人公司与论坛结构\n开场还引出最后的 OPC 圆桌。AI 降低执行成本后，一个人或小团队可以承担过去需要较大组织才能完成的创作与产品工作，但商业化、审美表达和持续运营仍然是问题。刘飞将从产品与个体经营角度主持 AJ 和抽象仔的讨论。王路平用“AI 是一道光”收束：技术带来可能性，但论坛更希望不同嘉宾用自己的实践照亮具体问题，让设计师重新找到行动的起点。","05 | Wang Luping: OPC and the structure of the forum\nThe opening frames the final roundtable around small-team capability, commercialisation, aesthetics and sustained operation.")],points:[t("Vibe Designing 不只讨论生成，也讨论审美、情绪和产品化。","Vibe Designing concerns aesthetics, emotion and productisation, not generation alone."),t("3D 与世界模型会推动设计流水线和负责人角色变化。","3D and world models reshape pipelines and design leadership."),t("AI 原住民的创作方式值得成年人反向学习。","AI-native creators offer a different model of learning and making."),t("OPC 的机会需要与商业、审美和持续运营一起讨论。","OPC opportunity must be discussed alongside business, aesthetics and sustained operation.")]});

Object.assign(talks.find(x=>x.id==="V08")!,{core:[
  t("01｜刘飞开题：OPC 到底是不是一件可操作的事？\n刘飞先介绍三人的位置：他曾是产品经理，现在以个体身份制作《三五环》《半拿铁》和“流言蜚语”；AJ 运营 AI 开源社区 WaytoAGI；抽象仔经营十人左右的 AI 内容工作室。刘飞把圆桌分成两条线：一条讨论 AI 是否让个人公司真正可行，另一条讨论个人创作中的设计与审美。他先请 AJ 解释，今天大家反复提到的 OPC 是否只是概念，还是已经具备现实条件。","01 | Liu Fei opens: is OPC actually workable?\nThe moderator introduces three different forms of independent practice and separates business feasibility from aesthetic expression."),
  t("02｜AJ：One Person Company 的 one 可以是虚数\nAJ 说自己经历了从质疑、理解到高度认可 OPC 的过程。WaytoAGI 承担大量社区与内容工作，全职成员仍只有几个人，很多任务依靠 AI 和网络协作完成。因此 one 不一定严格等于一个人，也可以是一支规模很小、借助系统放大能力的团队。政策与基础设施也在改善：他举亦庄 OPC 社区的例子，园区提供办公空间和快速注册服务，个人可以按 AI 硬件、软件、视频等类型更快完成公司设立。刘飞补充，浙江较高的政务数字化程度，也使个体经营比过去更具可行性。","02 | AJ: the one in OPC can be figurative\nSmall teams use AI, networks and supportive infrastructure to operate with the reach of much larger organisations."),
  t("03｜抽象仔：十个人也可以是一种 OPC\n抽象仔把自己的团队称为“十个人的 OPC”。AI 让每个成员的能力和创造力得到更充分释放，过去依赖央视或大型制作平台才能完成的内容，现在小团队也可以尝试。他同时提到模型幻觉的积极一面：在强烈创作意图与大量尝试下，系统偶尔会给出超出原先想象的结果。这里的 OPC 不是孤立劳动，而是小团队拥有更完整的创作自主权。","03 | Chouxiangzai: ten people can still operate like an OPC\nAI lets a small creative team attempt work once dependent on large institutions and occasionally discover unexpected results."),
  t("04｜抽象仔与刘飞：个人欲望、低俗内容和创作真诚\n刘飞追问，从《航拍中国》到霸总短剧和荒诞 AI 视频，抽象仔如何理解其中反差。抽象仔用玩笑表达：年轻时制作了太多价值调门很高的“善”的作品，AI 让身体里被压抑的“恶”和欲望快速呈现。他并不否认霸总内容的低俗，却认为其中有原生态、荒诞和讽刺的力量。成为更个人化的创作者后，他先满足自己的兴趣，结果反而找到更多同样感兴趣的观众。刘飞据此确认：这些内容不是为了商业化临时包装，而确实包含创作者自己的冲动和审美。","04 | Chouxiangzai and Liu Fei: desire, lowbrow content and sincerity\nThe creator explains how personal, absurd and even vulgar impulses can become honest artistic material rather than calculated packaging."),
  t("05｜抽象仔：商业收益可以与快乐创作同时发生\n抽象仔认为自己幸运之处在于，早期进入 AI 内容创作后，团队可以一边把作品当作艺术品打磨，一边获得商业利益。个人化不意味着拒绝市场；当作品来自真实兴趣，反而更容易形成辨识度。后来讨论流量时，他进一步强调“真诚”：创作者必须真正理解并喜欢内容，没必要依靠个人力量获得所有流量，只要把自己的一亩三分地耕好，与同样感兴趣的人建立连接。AIGC 让个体表达更直接，也让创作者内心世界是否完整变得更重要。","05 | Chouxiangzai: joyful creation and commercial return can coexist\nSincere knowledge of a narrow cultural territory can create both distinctive work and a viable audience."),
  t("06｜AJ：成为 OPC 需要综合能力，不只是会生成\n刘飞问 OPC 需要哪些条件。AJ 回答，很多人高调离开公司做 AI 创业，后来又回到大厂，因为真实商业交付远比 Demo 复杂。个人要理解财税、法律、合同、客户、交付与运营，不可能只做好一个局部。AI 能完成许多执行，但 OPC 必须看全局，至少对所有关键环节有基础认知。刘飞补充，工具第一次使用往往令人惊艳，但把效果变成稳定生产力和生意，是完全不同的挑战。","06 | AJ: OPC requires broad operational competence\nGeneration alone is insufficient; tax, law, contracts, clients, delivery and operations remain part of the business."),
  t("07｜AJ、刘飞与抽象仔：Token 成本正在成为商业约束\nAJ 举例，有创作者为了抽到一个镜头花费两万元积分，点击生成像赌博一样紧张。好模型越来越贵，不使用会与同行拉开差距，使用又会急剧增加成本；学生和小团队尤其难以负担。刘飞观察到，有设计师和程序员需要自费购买额度，招聘信息甚至把 Token 管够当作福利。抽象仔承认商业项目消耗很大，生成不是免费的无限产能。三人的共识是：AI 降低部分人力成本，却创造了新的算力、试错和筛选成本，OPC 必须把它们纳入报价与商业模型。","07 | AJ, Liu Fei and Chouxiangzai: token cost is a real business constraint\nCompute, experimentation and selection costs must be included in pricing rather than hidden behind the idea of free generation."),
  t("08｜刘飞与 AJ：小而具体的生意比宏大叙事更可行\n讨论转向产品市场。中国用户偏好 App，海外用户更习惯网站，因此网站产品和 Go to Market 服务存在新的需求。AJ 的社区开始帮助创作者处理产品市场化、增长、SEO 和对外叙事。刘飞总结，现在很多人不再先融资做巨大平台，而是解决一个具体问题、找到精准用户，让 AI 帮助补足前后环节。AJ 认同这种“小生意”路径：方向可以快速变化，关键看个人执行力、对 AI 的敏锐度和对细分市场的理解。刘飞提醒，AI 没有创造全新的商业基本规律，最终仍需要 To C 或 To B 的真实付费。","08 | Liu Fei and AJ: small, specific businesses may be more workable\nGTM, niche users and concrete paid problems matter more than inflated platform narratives."),
  t("09｜抽象仔：AI 创作人才首先看执行力与创造力\n刘飞问哪些人更适合 AI 创作。抽象仔说，团队从大量创作者中筛选成员时，不再只看名校或传统履历，而看是否愿意动手、能否吃苦、有没有个人创造力。AI 让想法很快可见，执行力因此更加重要；创造力也不是美院教育专属，每个人都可能有独特表达，只要能通过持续行动把它实现。他强调流量来自真诚和完整表达体系：个人彩蛋、文化共鸣与真实偏好，比为了覆盖所有人而制造的平均内容更有力量。","09 | Chouxiangzai: execution and creativity define AI talent\nThe team values making, endurance, personal imagination and a coherent inner world over conventional credentials alone."),
  t("10｜刘飞：大众产品越来越难，差异化连接更现实\n刘飞把内容创作与产品联系起来：一个青蛙吐纸的奇怪产品不必让所有人喜欢，但它可以连接审美和需求相近的一群人。今天再做一个所有人都使用的“大众品”非常困难，个人公司更适合找到差异化方向，用自己的喜好和判断与精准用户产生共鸣。这个逻辑既适用于内容，也适用于工具和服务：不追求抽象的大市场，而是把一个具体问题解决得足够鲜明。","10 | Liu Fei: universal products are harder than differentiated connection\nOPCs can build for a precise audience whose needs and taste align with the creator’s own judgment."),
  t("11｜AJ：最重要的基础能力是亲自动手\nAJ 把执行力放在 OPC 特质的首位。他运营社区时会亲自查看、测试和理解工具，再把经验分享出来；动手过程产生反馈，也暴露新的商业机会。他提到 FDE 这类角色：过去可能被称为外包交付，如今通过 Agent 能力快速进入行业，帮助客户把小功能和流程 AI 化。真正的能力不是背 Prompt，而是经过上百次操作理解模型特性，再结合某个行业持续服务。","11 | AJ: the primary capability is hands-on execution\nRepeated testing creates model intuition, feedback and service opportunities such as AI-enabled FDE work."),
  t("12｜刘飞与抽象仔：草率地开始，作品会带来下一步\n刘飞引用喜剧演员毛冬的话：“草率的开始，胜过深谋远虑的踌躇。”很多播客和内容项目不是准备完整后才上线，而是在制作中找到方向。抽象仔认同：AI 能把一个行动中的方案从 60 分推到 80 分，但如果不开始，它也无法优化。他回忆 2022 年 Midjourney 刚出现时为自己的 Hip-hop 歌曲制作封面，后来利用早年纪录片中“用有限镜头也要讲好故事”的经验进入 AI 视频。过去经历并未浪费，而是在新工具出现后重新连接起来。","12 | Liu Fei and Chouxiangzai: begin roughly, then let work produce the next step\nAI can improve an active project, but it cannot optimise an idea that never enters practice."),
  t("13｜AJ 与抽象仔：不要把 AGI 想成某天突然到来\n谈到焦虑，AJ 观察到明显断层：跟得快的人每天用 AI 完成大量工作，没跟上的人又面临工具越来越贵。但他仍然乐观，因为 AI 已经逐渐全民化，AGI 更可能是潜移默化发生，而不是某天宣布到来。不同职业和兴趣的人会突然借 AI 做出意外作品，下一次出圈未必来自精心策划。抽象仔也认为表达手段过去被资源垄断，AI 让更多人的内心世界能够投射出来，因此不必只从岗位消失的角度理解变化。","13 | AJ and Chouxiangzai: AGI may arrive gradually through widespread use\nCross-disciplinary creators and newly accessible forms of expression make the future uncertain but broadly generative."),
  t("14｜最后建议：不要盲目裸辞，但要立即开始积累\n刘飞先给出谨慎建议：商业模式尚未验证时不要因为一波工具热潮立刻裸辞。AJ 过去常说“出来最重要的是先出来”，但现在更建议先优化当前工作流，用 AI 节省时间，再把空出的时间投入实验。他以产品经理写文档为例，从早期就用录音转文字和 AI 处理工作，在岗位内建立了能力与资产。圆桌最终并没有给出一条统一创业路线，而是把风险与行动放在一起：先动手、先验证、持续积累，同时看清成本、交付和商业现实。","14 | Final advice: do not resign blindly, but begin accumulating now\nUse AI inside current work, free time for experiments, validate a business before jumping, and build assets through continued action.")],points:[t("AJ：OPC 的 one 可以是小团队，核心是用系统放大少量人的能力。","AJ: one can mean a small team; the core is system leverage."),t("抽象仔：个人创作的流量来自真诚、完整的表达体系和持续执行。","Chouxiangzai: sincere, coherent expression and execution create audience value."),t("刘飞：AI 不改变商业基本规律，产品仍需解决具体问题并获得真实付费。","Liu Fei: AI does not remove the need for a concrete problem and real payment."),t("三人共同讨论：Token、试错、财税、交付与运营都是 OPC 必须承担的成本。","All three: compute, experimentation, tax, delivery and operations remain real OPC costs."),t("刘飞与抽象仔：先开始，AI 才能帮助方案从可见走向可用。","Liu Fei and Chouxiangzai: begin first so AI has something real to improve."),t("最终建议不是立即裸辞，而是在现有工作中积累能力、资产和验证结果。","The final advice is to build capability and validation before resigning.")]});

