const ui={zh:{title:"7.11 D20｜原生创新 × Vibe Designing",sub:"两场分论坛整理",intro:"本页面整理了我在 7 月 11 日参与的两场分享：上午「AI 原生创新」与下午「云智能 / Vibe Designing」。通过场次、主题和内容类型快速浏览，也可以进入每个分享的详情，补齐核心内容与现场案例。",index:"分享目录",search:"搜索主题、分享人或观点…",all:"全部",native:"AI 原生创新",vibe:"云智能 / Vibe Designing",recommend:"推荐",why:"为什么推荐",back:"返回目录",core:"核心内容",points:"关键观点",images:"现场图片",next:"下一场分享",map:"设计对象如何迁移",past:"过去",now:"现在",happening:"正在发生"},en:{title:"7.11 D20 | AI-Native × Vibe Designing",sub:"Notes from two sub-forums",intro:"This page documents the two sessions I attended on 11 July: AI-Native Innovation in the morning and Cloud Intelligence / Vibe Designing in the afternoon. Browse by track, topic and content type, then open any talk for full context and cases.",index:"Talk Index",search:"Search topics, speakers or ideas…",all:"All",native:"AI-Native Innovation",vibe:"Cloud Intelligence / Vibe Designing",recommend:"Recommended",why:"Why it matters",back:"Back to index",core:"Core content",points:"Key takeaways",images:"Field images",next:"Next talk",map:"How the object of design is shifting",past:"Past",now:"Now",happening:"Emerging"}};

export default function Home(){
  const [lang,setLang]=useState<Lang>("zh"); const [track,setTrack]=useState("all"); const [kind,setKind]=useState("全部"); const [query,setQuery]=useState(""); const [selected,setSelected]=useState<string|null>(null); const [detailScrolled,setDetailScrolled]=useState(false); const U=ui[lang];
  const [zoomedImage,setZoomedImage]=useState<{src:string;label:string}|null>(null);
  const imagePanelRef=useRef<HTMLDivElement|null>(null);
  useEffect(()=>{
    const syncFromHistory=()=>setSelected(new URL(window.location.href).searchParams.get("talk"));
    syncFromHistory();
    window.addEventListener("popstate",syncFromHistory);
    return()=>window.removeEventListener("popstate",syncFromHistory);
  },[]);
  useEffect(()=>{
    if(!selected){setDetailScrolled(false);return;}
    const update=()=>setDetailScrolled(window.scrollY>150);
    update();window.addEventListener("scroll",update,{passive:true});
    return()=>window.removeEventListener("scroll",update);
  },[selected]);
  useEffect(()=>{
    if(!zoomedImage)return;
    const previousOverflow=document.body.style.overflow;
    const closeOnEscape=(event:KeyboardEvent)=>{if(event.key==="Escape")setZoomedImage(null);};
    document.body.style.overflow="hidden";window.addEventListener("keydown",closeOnEscape);
    return()=>{document.body.style.overflow=previousOverflow;window.removeEventListener("keydown",closeOnEscape);};
  },[zoomedImage]);
  useEffect(()=>{
    const panel=imagePanelRef.current;
    if(!selected||!panel)return;
    panel.dataset.loopReady="0";delete panel.dataset.loopTouched;
    const initialize=()=>{const segment=panel.querySelector<HTMLElement>(".visual-loop-segment");if(!segment||!segment.scrollHeight||panel.dataset.loopTouched==="1")return;panel.scrollTop=segment.offsetTop+segment.scrollHeight;panel.dataset.loopReady="1";};
    const segment=panel.querySelector<HTMLElement>(".visual-loop-segment");
    const observer=new ResizeObserver(initialize);if(segment)observer.observe(segment);
    const frame=requestAnimationFrame(()=>requestAnimationFrame(initialize));
    return()=>{cancelAnimationFrame(frame);observer.disconnect();};
  },[selected]);
  const shown=useMemo(()=>talks.filter(x=>(track==="all"||x.track===track)&&(kind==="全部"||x.type===kind)&&`${x.title.zh}${x.title.en}${x.speaker.zh}${x.overview.zh}${x.core.map(y=>y.zh)}`.toLowerCase().includes(query.toLowerCase())),[track,kind,query]);
  const talk=selected?talks.find(x=>x.id===selected):null;
  const openTalk=(id:string)=>{const url=new URL(window.location.href);url.searchParams.set("talk",id);window.history.pushState({talk:id},"",url);setZoomedImage(null);setSelected(id);window.scrollTo({top:0,behavior:"instant"});};
  const closeTalk=()=>{
    if(window.history.state?.talk)window.history.back();
    else{const url=new URL(window.location.href);url.searchParams.delete("talk");window.history.replaceState(null,"",url);setSelected(null);window.scrollTo({top:0,behavior:"instant"});}
  };
  const loopImagePanel=(panel:HTMLDivElement)=>{
    if(panel.dataset.loopReady!=="1"||panel.dataset.loopAdjusting)return;
    const firstSegment=panel.querySelector<HTMLElement>(".visual-loop-segment");
    if(!firstSegment)return;
    const segment=firstSegment.scrollHeight;const start=firstSegment.offsetTop;
    if(panel.scrollTop<start+segment*.5){
      panel.dataset.loopAdjusting="1";panel.scrollTop+=segment;
      requestAnimationFrame(()=>{delete panel.dataset.loopAdjusting;});
    }else if(panel.scrollTop>start+segment*1.5){
      panel.dataset.loopAdjusting="1";panel.scrollTop-=segment;
      requestAnimationFrame(()=>{delete panel.dataset.loopAdjusting;});
    }
  };
  if(talk){
    const talkIndex=talks.findIndex(x=>x.id===talk.id); const nextTalk=talks[(talkIndex+1)%talks.length];
    const imageSequence=talk.images||[];
    return <main className="talk-page"><div className={`detail-top ${detailScrolled?"is-scrolled":""}`}><button className="floating-back" onClick={closeTalk} aria-label={U.back}><span className="back-arrow">←</span><span className="back-label">{U.back}</span></button><button className="lang" onClick={()=>setLang(lang==="zh"?"en":"zh")}>{lang==="zh"?"EN":"中文"}</button></div><header className="talk-hero"><div><span>{talk.id} / {talk.track==="native"?U.native:U.vibe}</span>{talk.recommended&&<b>{U.recommend}</b>}</div><h1>{talk.title[lang]}</h1><div className="speaker"><p>{talk.speaker[lang]}</p><span>{talk.role[lang]}</span></div><p className="overview">{talk.overview[lang]}</p></header><section className="takeaways"><div className="section-kicker">01 / {U.points}</div><div className="takeaway-grid">{talk.points.map((p,i)=><article key={i}><span>{String(i+1).padStart(2,"0")}</span><p>{p[lang]}</p></article>)}</div>{talk.reason&&<div className="recommend"><b>{U.recommend} · {U.why}</b><p>{talk.reason[lang]}</p></div>}</section><section className={`reading-grid ${talk.images?.length?"has-images":""}`}><article className="article-copy"><span>02 / {U.core}</span>{talk.core.map((p,i)=><div className="story-section" key={i}><p className="story-p">{p[lang]}</p>{talk.id==="N01"&&i===1&&<a className="watch-link" href="https://www.bilibili.com/video/BV1sUcgzWEux/" target="_blank" rel="noreferrer"><span>{lang==="zh"?"观看作品":"Watch the film"}</span><strong>《恐鸟》 / BILIBILI</strong><i>↗</i></a>}</div>)}</article>{talk.images?.length&&<aside className="visual-rail"><div className="visual-rail-window" ref={imagePanelRef} onScroll={e=>loopImagePanel(e.currentTarget)} onWheel={e=>{e.currentTarget.dataset.loopTouched="1"}} onTouchStart={e=>{e.currentTarget.dataset.loopTouched="1"}} onPointerDown={e=>{e.currentTarget.dataset.loopTouched="1"}}><div className="visual-rail-head"><span>03 / {U.images}</span><small>{lang==="zh"?"↕ 无限图片流 / 独立滚动":"↕ Infinite image stream / independent scroll"}</small></div>{[0,1,2].map(segment=><div className="visual-loop-segment" key={segment} aria-hidden={segment!==1}>{imageSequence.map((src,i)=><figure key={`${segment}-${i}-${src}`}><img src={src} alt={segment===1?`${talk.title[lang]} 现场图片 ${i%talk.images!.length+1}`:""}/><button className="image-zoom" type="button" tabIndex={segment===1?0:-1} aria-label={lang==="zh"?"放大图片":"Enlarge image"} onClick={()=>setZoomedImage({src,label:`${talk.id} / IMAGE ${String(i%talk.images!.length+1).padStart(2,"0")}`})}><span>⛶</span>{lang==="zh"?"放大":"View"}</button><figcaption>{talk.id} / IMAGE {String(i%talk.images!.length+1).padStart(2,"0")}</figcaption></figure>)}</div>)}</div></aside>}</section>{zoomedImage&&<div className="lightbox" role="dialog" aria-modal="true" aria-label={lang==="zh"?"图片放大预览":"Enlarged image preview"} onClick={()=>setZoomedImage(null)}><div className="lightbox-panel" onClick={e=>e.stopPropagation()}><button className="lightbox-close" type="button" autoFocus onClick={()=>setZoomedImage(null)} aria-label={lang==="zh"?"关闭预览":"Close preview"}>×</button><img src={zoomedImage.src} alt={zoomedImage.label}/><p>{zoomedImage.label}</p></div></div>}<nav className="next-talk" aria-label={U.next}><button onClick={()=>openTalk(nextTalk.id)}><span>{U.next} · {nextTalk.id}</span><strong>{nextTalk.title[lang]}</strong><i>→</i></button></nav><footer><div><b>YVEN’S NOTES</b><br/>FROM 2026 ALIBABA DESIGN D20</div><div>{talk.speaker[lang]}<br/>{talk.role[lang]}</div><div className="green">READ / QUESTION / REFRAME</div></footer></main>;
  }
  return <main><header className="masthead"><div className="topline"><span>D20 / 2026</span><span>AI 设计 · 新应用</span><button className="lang" onClick={()=>setLang(lang==="zh"?"en":"zh")}>{lang==="zh"?"EN":"中文"}</button></div><div className="hero-grid"><div className="issue">FIELD<br/>NOTES<br/><b>№ 01</b></div><div><p className="eyebrow">{U.sub}</p><h1>{lang==="zh"?<>7.11 D20<br/><i>原生创新 × Vibe Designing</i></>:<>7.11 D20<br/><i>AI-Native × Vibe Designing</i></>}</h1></div><div className="abstract"><div className="orb"/><p>AI-NATIVE / AM<br/>VIBE DESIGNING / PM</p></div></div><div className="intro"><p>{U.intro}</p><p>{talks.length} TALKS · 2 TRACKS<br/>HANGZHOU / 2026.07.11</p></div></header><section className="archive" id="archive"><div className="archive-head"><div><span>01 / TALK INDEX</span><h2>{U.index}</h2></div><div className="result">{String(shown.length).padStart(2,"0")} / {talks.length}</div></div><div className="controls"><label className="search"><span>SEARCH</span><input value={query} onChange={e=>setQuery(e.target.value)} placeholder={U.search}/></label><div className="filter wide"><span>TRACK / 场次</span><div><button className={track==="all"?"active":""} onClick={()=>setTrack("all")}>{U.all}</button><button className={track==="native"?"active":""} onClick={()=>setTrack("native")}>{U.native}</button><button className={track==="vibe"?"active":""} onClick={()=>setTrack("vibe")}>{U.vibe}</button></div></div><div className="filter"><span>TYPE / 类型</span><div>{["全部","观点","方法论","案例","工具"].map(x=><button className={kind===x?"active":""} onClick={()=>setKind(x)} key={x}>{lang==="en"&&x==="全部"?"All":x}</button>)}</div></div></div><div className="cards">{shown.map(item=><article className="card" key={item.id}><button className="card-main" onClick={()=>openTalk(item.id)}><span className="num">({item.id})</span><span className="meta">{item.track==="native"?U.native:U.vibe}<br/><b>{item.type}</b></span><span className="copy"><span className="speaker-line">{item.speaker[lang]} · {item.role[lang]}</span><h3>{item.title[lang]}</h3><p>{item.overview[lang]}</p>{item.recommended&&<strong className="pick">✳ {U.recommend}</strong>}</span><span className="toggle">→</span></button></article>)}</div></section><section className="map"><span>02 / SHIFT MAP</span><h2>{U.map}</h2><div className="map-grid"><div><b>{U.past}</b><h3>Pixels</h3><p>Layers · Pages · Static handoff</p></div><i>→</i><div><b>{U.now}</b><h3>Intent</h3><p>Context · Direction · Dynamic UX</p></div><i>→</i><div className="future"><b>{U.happening}</b><h3>Runtime</h3><p>Rules · Skill · Agent · Validation</p></div></div></section><footer><div><b>YVEN’S NOTES</b><br/>FROM 2026 ALIBABA DESIGN D20</div><div>AI-NATIVE INNOVATION / AM<br/>VIBE DESIGNING / PM</div><div className="green">READ / QUESTION / REFRAME</div></footer></main>;
}
